 11→function confirmPrompt(message: string): Promise<boolean> {
 12→  const rl = createInterface({ input: process.stdin, output: process.stdout });
 13→  return new Promise((resolve) => {
 14→    rl.question(`${message} [y/N] `, (answer) => {
 15→      rl.close();
 16→      resolve(answer.trim().toLowerCase() === 'y');
 17→    });
 18→  });
 19→}
