 27→async function checkServer(baseUrl: string): Promise<void> {
 28→  try {
 29→    await fetch(`${baseUrl}/api/health`);
 30→  } catch {
 31→    console.log(chalk.yellow('  Dashboard server is not running.'));
 32→    console.log(chalk.dim('  Start it with: code-insights dashboard'));
 33→    console.log();
 34→    process.exit(1);
 35→  }
 36→}
