 55→// ---------------------------------------------------------------------------
 56→// SSE helpers
 57→// ---------------------------------------------------------------------------
 58→
 59→async function fetchWithSSE(url: string, body: Record<string, unknown>, signal?: AbortSignal): Promise<Record<string, unknown>> {
 60→  const res = await fetch(url, {
 61→    method: 'POST',
 62→    headers: { 'Content-Type': 'application/json' },
 63→    body: JSON.stringify(body),
 64→    signal,
 65→  });
 66→
 67→  if (!res.ok) {
 68→    const text = await res.text().catch(() => res.statusText);
 69→    throw new Error(`Server error ${res.status}: ${text}`);
 70→  }
 71→
 72→  if (!res.body) throw new Error('No response body');
 73→
 74→  const reader = res.body.pipeThrough(new TextDecoderStream()).getReader();
 75→  let buffer = '';
 76→  let currentEvent = '';
 77→  let currentData = '';
 78→  let result: Record<string, unknown> = {};
 79→
 80→  const spinner = ora({ text: 'Starting...', indent: 2 }).start();
 81→
 82→  try {
 83→    while (true) {
 84→      const { done, value } = await reader.read();
 85→      if (done) break;
 86→
 87→      buffer += value;
 88→      const lines = buffer.split('\n');
 89→      buffer = lines.pop() ?? '';
 90→
 91→      for (const line of lines) {
 92→        if (line.startsWith('event: ')) {
 93→          currentEvent = line.slice(7).trim();
 94→        } else if (line.startsWith('data: ')) {
 95→          currentData = line.slice(6);
 96→        } else if (line === '' && currentEvent && currentData) {
 97→          try {
 98→            const data = JSON.parse(currentData) as Record<string, unknown>;
 99→
100→            if (currentEvent === 'progress') {
101→              spinner.text = (data.message as string) || 'Processing...';
102→            } else if (currentEvent === 'complete') {
103→              spinner.succeed('Analysis complete');
104→              result = data;
105→            } else if (currentEvent === 'error') {
106→              spinner.fail((data.error as string) || 'Generation failed');
107→            }
108→          } catch {
109→            // Skip malformed SSE events (e.g., truncated JSON from network issues)
110→          }
111→
112→          currentEvent = '';
113→          currentData = '';
114→        }
115→      }
116→    }
117→  } finally {
118→    reader.releaseLock();
119→  }
120→
121→  return result;
122→}
123→
124→async function backfillBatch(
125→  baseUrl: string,
126→  sessionIds: string[],
127→  offset: number,
128→  total: number,
129→  signal?: AbortSignal
130→): Promise<{ completed: number; failed: number }> {
131→  const res = await fetch(`${baseUrl}/api/facets/backfill`, {
132→    method: 'POST',
133→    headers: { 'Content-Type': 'application/json' },
134→    body: JSON.stringify({ sessionIds }),
135→    signal,
136→  });
137→
138→  if (!res.ok) {
139→    const text = await res.text().catch(() => res.statusText);
140→    throw new Error(`Server error ${res.status}: ${text}`);
141→  }
142→  if (!res.body) throw new Error('No response body');
143→
144→  const reader = res.body.pipeThrough(new TextDecoderStream()).getReader();
145→  let buffer = '';
146→  let currentEvent = '';
147→  let currentData = '';
148→  let result = { completed: 0, failed: 0 };
149→
150→  const spinner = ora({ text: `  Backfilling ${offset + 1}-${offset + sessionIds.length} of ${total}...`, indent: 2 }).start();
151→
152→  try {
153→    while (true) {
154→      const { done, value } = await reader.read();
155→      if (done) break;
156→      buffer += value;
157→      const lines = buffer.split('\n');
158→      buffer = lines.pop() ?? '';
159→      for (const line of lines) {
160→        if (line.startsWith('event: ')) {
161→          currentEvent = line.slice(7).trim();
162→        } else if (line.startsWith('data: ')) {
163→          currentData = line.slice(6);
164→        } else if (line === '' && currentEvent && currentData) {
165→          try {
166→            const data = JSON.parse(currentData) as Record<string, unknown>;
167→            if (currentEvent === 'progress') {
168→              const processed = (data.completed as number) + (data.failed as number);
169→              spinner.text = `  Backfilling ${offset + processed + 1} of ${total}...`;
170→            } else if (currentEvent === 'complete') {
171→              result = { completed: data.completed as number, failed: data.failed as number };
172→              spinner.succeed(`  Batch complete: ${result.completed} extracted, ${result.failed} failed`);
173→            }
174→          } catch { /* skip malformed */ }
175→          currentEvent = '';
176→          currentData = '';
177→        }
178→      }
179→    }
180→  } finally {
181→    reader.releaseLock();
182→  }
183→  return result;
184→}
