190→async function reflectAction(options: {
191→  section?: string;
192→  period?: string;
193→  project?: string;
194→}): Promise<void> {
195→  const baseUrl = getBaseUrl();
196→
197→  await checkServer(baseUrl);
198→
199→  // Check minimum session threshold
200→  const checkParams = new URLSearchParams();
201→  checkParams.set('period', options.period || '30d');
202→  if (options.project) checkParams.set('project', options.project);
203→  const aggRes = await fetch(`${baseUrl}/api/facets/aggregated?${checkParams.toString()}`);
204→  if (aggRes.ok) {
205→    const agg = await aggRes.json() as { totalSessions: number; totalAllSessions: number };
206→    if (agg.totalSessions < 20) {
207→      console.log(chalk.yellow(`  Not enough analyzed sessions for meaningful synthesis.`));
208→      console.log(chalk.dim(`  Need at least 20 sessions with facets (currently ${agg.totalSessions}).`));
209→      console.log(chalk.dim(`  Run session analysis to extract facets from more sessions.`));
210→      console.log();
211→      process.exit(1);
212→    }
213→
214→    if (agg.totalAllSessions > 0 && agg.totalSessions / agg.totalAllSessions < 0.5) {
215→      console.log(chalk.yellow(`  Note: Only ${agg.totalSessions} of ${agg.totalAllSessions} sessions are analyzed.`));
216→      console.log(chalk.dim(`  Results may not represent your full patterns.`));
217→      console.log();
218→    }
219→  }
220→
221→  const body: Record<string, unknown> = {
222→    period: options.period || '30d',
223→  };
224→  if (options.section) {
225→    body.sections = [options.section];
226→  }
227→  if (options.project) {
228→    body.project = options.project;
229→  }
230→
231→  console.log();
232→  const data = await fetchWithSSE(`${baseUrl}/api/reflect/generate`, body);
233→
234→  // Display results summary
235→  const results = data.results as Record<string, Record<string, unknown>> | undefined;
236→  if (!results) {
237→    console.log(chalk.dim('  No results generated.'));
238→    return;
239→  }
240→
241→  console.log();
242→
243→  // Friction & Wins summary
244→  const frictionWins = results['friction-wins'];
245→  if (frictionWins) {
246→    console.log(chalk.bold('  Friction & Wins'));
247→    if (frictionWins.narrative) {
248→      const lines = String(frictionWins.narrative).split('\n');
249→      for (const line of lines) {
250→        console.log(chalk.dim('  ') + line);
251→      }
252→    }
253→    console.log();
254→  }
255→
256→  // Rules & Hooks summary
257→  const rulesSkills = results['rules-skills'];
258→  if (rulesSkills) {
259→    console.log(chalk.bold('  Rules & Hooks'));
260→    const rules = rulesSkills.claudeMdRules as Array<{ rule: string }> | undefined;
261→    if (rules && rules.length > 0) {
262→      console.log(chalk.dim('  CLAUDE.md rules:'));
263→      for (const r of rules) {
264→        console.log(`    ${chalk.cyan('→')} ${r.rule}`);
265→      }
266→    }
267→    const hooks = rulesSkills.hookConfigs as Array<{ event: string; command: string }> | undefined;
268→    if (hooks && hooks.length > 0) {
269→      console.log(chalk.dim('  Hooks:'));
270→      for (const h of hooks) {
271→        console.log(`    ${chalk.cyan('→')} ${h.event}: ${h.command}`);
272→      }
273→    }
274→    console.log();
275→  }
276→
277→  // Working Style summary
278→  const workingStyle = results['working-style'];
279→  if (workingStyle) {
280→    console.log(chalk.bold('  Working Style'));
281→    if (workingStyle.narrative) {
282→      const lines = String(workingStyle.narrative).split('\n');
283→      for (const line of lines) {
284→        console.log(chalk.dim('  ') + line);
285→      }
286→    }
287→    console.log();
288→  }
289→
290→  console.log(chalk.dim('  View full results: code-insights dashboard → Patterns'));
291→  console.log();
292→}
