294→const BACKFILL_BATCH_SIZE = 200;
295→
296→async function backfillAction(options: {
297→  period?: string;
298→  project?: string;
299→  dryRun?: boolean;
300→}): Promise<void> {
301→  const baseUrl = getBaseUrl();
302→  await checkServer(baseUrl);
303→  await checkLlmConfigured(baseUrl);
304→
305→  const params = new URLSearchParams();
306→  params.set('period', options.period || 'all');
307→  if (options.project) params.set('project', options.project);
308→
309→  const res = await fetch(`${baseUrl}/api/facets/missing?${params.toString()}`);
310→  if (!res.ok) {
311→    const text = await res.text().catch(() => res.statusText);
312→    console.log(chalk.red(`  Error: ${text}`));
313→    process.exit(1);
314→  }
315→
316→  const { sessionIds, count } = await res.json() as { sessionIds: string[]; count: number };
317→
318→  console.log();
319→  if (count === 0) {
320→    console.log(chalk.green('  All analyzed sessions already have facets.'));
321→    console.log();
322→    return;
323→  }
324→
325→  console.log(chalk.cyan(`  Found ${count} session${count !== 1 ? 's' : ''} with insights but missing facets.`));
326→  console.log(chalk.dim(`  This will make ${count} LLM call${count !== 1 ? 's' : ''}.`));
327→
328→  if (options.dryRun) {
329→    console.log(chalk.dim('  (dry run — no changes made)'));
330→    console.log();
331→    return;
332→  }
333→
334→  // Confirm before proceeding — each call costs tokens
335→  const confirmed = await confirmPrompt('  Continue?');
336→  if (!confirmed) {
337→    console.log(chalk.dim('  Aborted.'));
338→    console.log();
339→    return;
340→  }
341→
342→  console.log();
343→
344→  let totalCompleted = 0;
345→  let totalFailed = 0;
346→
347→  for (let i = 0; i < sessionIds.length; i += BACKFILL_BATCH_SIZE) {
348→    const batch = sessionIds.slice(i, i + BACKFILL_BATCH_SIZE);
349→    const { completed, failed } = await backfillBatch(baseUrl, batch, i, sessionIds.length);
350→    totalCompleted += completed;
351→    totalFailed += failed;
352→  }
353→
354→  console.log();
355→  console.log(chalk.bold('  Summary'));
356→  console.log(chalk.green(`    ${totalCompleted} sessions backfilled`));
357→  if (totalFailed > 0) {
358→    console.log(chalk.yellow(`    ${totalFailed} sessions failed`));
359→  }
360→  console.log();
361→}
