364→// Command registration
365→// ---------------------------------------------------------------------------
366→
367→const backfillCommand = new Command('backfill')
368→  .description('Extract facets for sessions that have insights but are missing pattern data')
369→  .option('-p, --period <period>', 'Time range: 7d, 30d, 90d, all', 'all')
370→  .option('--project <name>', 'Scope to a single project')
371→  .option('--dry-run', 'Show count without backfilling')
372→  .action(backfillAction);
373→
374→export const reflectCommand = new Command('reflect')
375→  .description('Generate cross-session analysis (friction, rules, working style)')
376→  .option('--section <name>', 'Generate specific section: friction-wins, rules-skills, working-style')
377→  .option('-p, --period <period>', 'Time range: 7d, 30d, 90d, all', '30d')
378→  .option('--project <name>', 'Scope to a single project')
379→  .addCommand(backfillCommand)
380→  .action(reflectAction);
