  1→// Synthesis prompts for the Reflect/Patterns feature.
  2→// These prompts receive pre-aggregated facet data and produce cross-session narratives.
  3→// LLMs synthesize — they don't count. All counting is done in code before calling these.
  4→
  5→// --- Friction & Wins ---
  6→
  7→export const FRICTION_WINS_SYSTEM_PROMPT = `You are analyzing cross-session patterns from a developer's AI coding sessions. You will receive pre-aggregated friction categories and effective patterns with counts and severity scores.
  8→
  9→Your job is to synthesize a narrative analysis of the 3-5 most significant patterns. For each pattern:
 10→1. State what the pattern is
 11→2. Explain why it matters (impact on productivity)
 12→3. Identify the likely root cause
 13→4. Note if it's trending (getting better or worse)
 14→
 15→RULES:
 16→- Every claim must trace to the statistics provided. Do not invent patterns.
 17→- Patterns require 2+ occurrences to be mentioned.
 18→- Do not give advice — that's for the Rules & Skills section.
 19→- Be specific: "wrong-approach appeared 7 times with high severity" not "there were some issues"
 20→- Keep the narrative under 500 words.
 21→
 22→Respond with valid JSON only, wrapped in <json>...</json> tags.`;
 23→
 24→export function generateFrictionWinsPrompt(data: {
 25→  frictionCategories: Array<{ category: string; count: number; avg_severity: number; examples: string[] }>;
 26→  effectivePatterns: Array<{ description: string; frequency: number; avg_confidence: number }>;
 27→  totalSessions: number;
 28→  period: string;
 29→}): string {
 30→  return `Analyze these cross-session patterns from ${data.totalSessions} sessions over ${data.period}.
 31→
 32→FRICTION CATEGORIES (ranked by frequency × severity):
 33→${JSON.stringify(data.frictionCategories.slice(0, 15), null, 2)}
 34→
 35→EFFECTIVE PATTERNS (ranked by frequency):
 36→${JSON.stringify(data.effectivePatterns.slice(0, 10), null, 2)}
 37→
 38→Respond with this JSON format:
 39→{
 40→  "narrative": "Your 300-500 word analysis of the most significant patterns",
 41→  "topFriction": [
 42→    {
 43→      "category": "category-name",
 44→      "significance": "Why this matters",
 45→      "rootCause": "Likely underlying cause",
 46→      "trend": "increasing | stable | decreasing | new"
 47→    }
 48→  ],
 49→  "topWins": [
 50→    {
 51→      "pattern": "Description of what works",
 52→      "significance": "Why this is effective"
 53→    }
 54→  ]
 55→}
 56→
 57→Respond with valid JSON only, wrapped in <json>...</json> tags.`;
 58→}
 59→
 60→// --- Rules & Skills ---
 61→
 62→export const RULES_SKILLS_SYSTEM_PROMPT = `You are generating actionable artifacts from cross-session analysis of a developer's AI coding sessions. You will receive recurring friction patterns and effective practices.
 63→
 64→Your job is to produce concrete, copy-paste-ready artifacts:
 65→1. CLAUDE.md rules — specific instructions to add to the AI assistant's config
 66→2. Hook configurations — automation triggers
 67→
 68→RULES:
 69→- Only generate artifacts for patterns with 3+ occurrences (friction) or 2+ occurrences (effective patterns)
 70→- Rules must be specific enough to be actionable: "Always run tests before creating PRs" not "Be careful with code"
 71→- Hook configs must include the event trigger and command
 72→- Max 6 rules, 3 hooks
 73→- Each artifact must reference the friction pattern or effective practice it addresses
 74→
 75→Respond with valid JSON only, wrapped in <json>...</json> tags.`;
 76→
 77→export function generateRulesSkillsPrompt(data: {
 78→  recurringFriction: Array<{ category: string; count: number; avg_severity: number; examples: string[] }>;
 79→  effectivePatterns: Array<{ description: string; frequency: number; avg_confidence: number }>;
 80→  antiPatterns?: Array<{ name: string; count: number; examples: string[] }>;
 81→  targetTool: string;
 82→}): string {
 83→  return `Generate actionable artifacts from these recurring patterns.
 84→
 85→TARGET TOOL: ${data.targetTool} (generate artifacts compatible with this tool's ecosystem)
 86→
 87→RECURRING FRICTION (3+ occurrences):
 88→${JSON.stringify(data.recurringFriction, null, 2)}
 89→
 90→EFFECTIVE PATTERNS (2+ occurrences):
 91→${JSON.stringify(data.effectivePatterns, null, 2)}
 92→
 93→${data.antiPatterns ? `PROMPT ANTI-PATTERNS:\n${JSON.stringify(data.antiPatterns, null, 2)}` : ''}
 94→
 95→Respond with this JSON format:
 96→{
 97→  "claudeMdRules": [
 98→    {
 99→      "rule": "The exact text to add to CLAUDE.md",
100→      "rationale": "Why this rule helps (reference the friction pattern)",
101→      "frictionSource": "category-name (N occurrences)"
102→    }
103→  ],
104→  "hookConfigs": [
105→    {
106→      "event": "pre-commit | post-file-edit | etc.",
107→      "command": "The shell command to run",
108→      "rationale": "Why this automation helps"
109→    }
110→  ]
111→}
112→
113→Respond with valid JSON only, wrapped in <json>...</json> tags.`;
114→}
