  5→import chalk from 'chalk';
  6→import ora from 'ora';
  7→import type { StatsFlags } from '../data/types.js';
  8→import { resolveDataSource } from '../data/source.js';
  9→import { handleStatsError } from './error-handler.js';
 10→import { loadConfig } from '../../../utils/config.js';
 11→import { sectionHeader } from '../render/layout.js';
 12→
 13→interface AggregatedData {
 14→  frictionCategories: Array<{
 15→    category: string;
 16→    count: number;
 17→    avg_severity: number;
 18→    examples: string[];
 19→  }>;
 20→  effectivePatterns: Array<{
 21→    description: string;
 22→    frequency: number;
 23→    avg_confidence: number;
 24→  }>;
 25→  outcomeDistribution: Record<string, number>;
 26→  workflowDistribution: Record<string, number>;
 27→  characterDistribution: Record<string, number>;
 28→  totalSessions: number;
 29→  frictionTotal: number;
 30→  totalAllSessions: number;
 31→}
 32→
 33→export async function patternsAction(flags: StatsFlags): Promise<void> {
 34→  try {
 35→    const source = await resolveDataSource(flags);
 36→
 37→    // Sync first unless --no-sync
 38→    if (!flags.noSync) {
 39→      const spinner = ora({ text: 'Syncing...', indent: 2 }).start();
 40→      try {
 41→        const prepResult = await source.prepare(flags);
 42→        spinner.succeed(prepResult.message);
 43→      } catch {
 44→        spinner.warn('Sync failed (showing cached data)');
 45→      }
 46→    }
 47→
 48→    const config = loadConfig();
 49→    const port = config?.dashboard?.port || 7890;
 50→    const baseUrl = `http://localhost:${port}`;
 51→
 52→    // Check if server is running
 53→    try {
 54→      await fetch(`${baseUrl}/api/health`);
 55→    } catch {
 56→      console.log();
 57→      console.log(chalk.yellow('  Dashboard server is not running.'));
 58→      console.log(chalk.dim('  Start it with: code-insights dashboard'));
 59→      console.log();
 60→      return;
 61→    }
 62→
 63→    // Fetch aggregated data
 64→    const params = new URLSearchParams();
 65→    params.set('period', flags.period);
 66→    if (flags.project) params.set('project', flags.project);
 67→    if (flags.source) params.set('source', flags.source);
 68→
 69→    const res = await fetch(`${baseUrl}/api/reflect/results?${params.toString()}`);
 70→    if (!res.ok) {
 71→      console.log(chalk.red(`  Failed to fetch patterns: ${res.statusText}`));
 72→      return;
 73→    }
 74→
 75→    const data = await res.json() as AggregatedData;
 76→
 77→    if (data.totalSessions === 0) {
 78→      console.log();
 79→      console.log(chalk.dim('  No sessions with facets found.'));
