  1→import { Hono } from 'hono';
  2→import { streamSSE } from 'hono/streaming';
  3→import { getDb } from '@code-insights/cli/db/client';
  4→import { isLLMConfigured } from '../llm/client.js';
  5→import { extractFacetsOnly } from '../llm/analysis.js';
  6→import type { SQLiteMessageRow, SessionData } from '../llm/analysis.js';
  7→import { buildWhereClause, getAggregatedData } from './shared-aggregation.js';
  8→
  9→const app = new Hono();
 10→
 11→const MAX_BACKFILL_SESSIONS = 200;
 12→
 13→interface FacetRow {
 14→  session_id: string;
 15→  outcome_satisfaction: string;
 16→  workflow_pattern: string | null;
 17→  had_course_correction: number;
 18→  course_correction_reason: string | null;
 19→  iteration_count: number;
 20→  friction_points: string;     // JSON
 21→  effective_patterns: string;  // JSON
 22→  extracted_at: string;
 23→  analysis_version: string;
 24→}
 25→
 26→// GET /api/facets
 27→// Query params: project (project_id), period (7d|30d|90d|all), source (source_tool filter)
 28→// Returns: { facets, missingCount, totalSessions }
 29→app.get('/', (c) => {
 30→  const db = getDb();
 31→  const project = c.req.query('project');
 32→  const period = c.req.query('period') || '30d';
 33→  const source = c.req.query('source');
 34→
 35→  const { where, params } = buildWhereClause(period, project, source);
 36→
 37→  // Total sessions in scope
 38→  const totalRow = db.prepare(
 39→    `SELECT COUNT(*) as count FROM sessions s ${where}`
 40→  ).get(...params) as { count: number };
 41→
 42→  // Sessions with facets — join to sessions so period/project/source filters apply
 43→  const facets = db.prepare(
 44→    `SELECT sf.* FROM session_facets sf
 45→     JOIN sessions s ON sf.session_id = s.id
 46→     ${where}
 47→     ORDER BY s.started_at DESC`
 48→  ).all(...params) as FacetRow[];
 49→
 50→  return c.json({
 51→    facets,
 52→    missingCount: totalRow.count - facets.length,
 53→    totalSessions: totalRow.count,
 54→  });
 55→});
 56→
 57→// GET /api/facets/aggregated
 58→// Returns pre-aggregated friction categories and effective patterns for synthesis.
 59→// Uses the shared getAggregatedData function to avoid duplication with reflect routes.
 60→app.get('/aggregated', (c) => {
 61→  const db = getDb();
 62→  const project = c.req.query('project');
 63→  const period = c.req.query('period') || '30d';
 64→  const source = c.req.query('source');
 65→
 66→  const { where, params } = buildWhereClause(period, project, source);
 67→  const aggregated = getAggregatedData(db, where, params, project, source);
 68→
 69→  return c.json(aggregated);
 70→});
 71→
 72→// GET /api/facets/missing
 73→// Returns session IDs that have insights but no session_facets row.
 74→// Used by CLI `reflect backfill` and dashboard facet status indicators.
 75→app.get('/missing', (c) => {
 76→  const db = getDb();
 77→  const period = c.req.query('period') || 'all';
 78→  const project = c.req.query('project');
 79→  const source = c.req.query('source');
 80→
 81→  // buildWhereClause can't be used here — it generates "WHERE ..." prefix,
 82→  // but this query already needs "WHERE sf.session_id IS NULL".
 83→  // Build conditions inline instead.
 84→  const conditions: string[] = ['sf.session_id IS NULL', 's.deleted_at IS NULL'];
 85→  const params: (string | number)[] = [];
 86→
 87→  if (period !== 'all') {
 88→    const now = new Date();
 89→    const days = period === '7d' ? 7 : period === '30d' ? 30 : period === '90d' ? 90 : 0;
 90→    if (days > 0) {
 91→      conditions.push('s.started_at >= ?');
 92→      params.push(new Date(now.getTime() - days * 86400000).toISOString());
 93→    }
 94→  }
 95→  if (project) {
 96→    conditions.push('s.project_id = ?');
 97→    params.push(project);
 98→  }
 99→  if (source) {
100→    conditions.push('s.source_tool = ?');
101→    params.push(source);
102→  }
103→
104→  const where = `WHERE ${conditions.join(' AND ')}`;
105→
106→  const rows = db.prepare(`
107→    SELECT DISTINCT i.session_id
108→    FROM insights i
109→    JOIN sessions s ON i.session_id = s.id
110→    LEFT JOIN session_facets sf ON i.session_id = sf.session_id
111→    ${where}
112→  `).all(...params) as Array<{ session_id: string }>;
113→
114→  const sessionIds = rows.map(r => r.session_id);
115→  return c.json({ sessionIds, count: sessionIds.length });
116→});
117→
118→// POST /api/facets/backfill
119→// Body: { sessionIds: string[] }
120→// Streams progress as facets are extracted one-by-one for sessions that lack them.
121→// Uses extractFacetsOnly (lightweight prompt: summary + first/last 20 messages).
122→app.post('/backfill', async (c) => {
123→  if (!isLLMConfigured()) {
124→    return c.json({ error: 'LLM not configured.' }, 400);
125→  }
126→
127→  const body = await c.req.json<{ sessionIds?: string[] }>();
128→  if (!body.sessionIds || !Array.isArray(body.sessionIds) || body.sessionIds.length === 0) {
129→    return c.json({ error: 'sessionIds array required' }, 400);
130→  }
131→  if (body.sessionIds.length > MAX_BACKFILL_SESSIONS) {
132→    return c.json({ error: `Maximum ${MAX_BACKFILL_SESSIONS} sessions per backfill request` }, 400);
133→  }
134→
135→  const db = getDb();
136→
137→  return streamSSE(c, async (stream) => {
138→    const abortSignal = c.req.raw.signal;
139→    let completed = 0;
140→    let failed = 0;
141→    const total = body.sessionIds!.length;
142→
143→    for (const sessionId of body.sessionIds!) {
144→      if (abortSignal.aborted) break;
145→
146→      const session = db.prepare(
147→        `SELECT id, project_id, project_name, project_path, summary, ended_at
148→         FROM sessions WHERE id = ? AND deleted_at IS NULL`
149→      ).get(sessionId) as SessionData | undefined;
150→
151→      if (!session) {
152→        failed++;
153→        await stream.writeSSE({
154→          event: 'progress',
155→          data: JSON.stringify({
156→            completed,
157→            failed,
158→            total,
159→            currentSessionId: sessionId,
160→          }),
161→        });
162→        continue;
163→      }
164→
165→      // Skip sessions that already have facets (race condition guard)
166→      const existingFacet = db.prepare(
167→        'SELECT 1 FROM session_facets WHERE session_id = ?'
168→      ).get(sessionId);
169→      if (existingFacet) {
170→        completed++;
171→        await stream.writeSSE({
172→          event: 'progress',
173→          data: JSON.stringify({
174→            completed,
175→            failed,
176→            total,
177→            currentSessionId: sessionId,
178→          }),
179→        });
180→        continue;
181→      }
182→
183→      // Only load first 20 and last 20 messages for facet extraction
184→      const firstMessages = db.prepare(
185→        `SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
186→         FROM messages WHERE session_id = ? ORDER BY timestamp ASC LIMIT 20`
187→      ).all(sessionId) as SQLiteMessageRow[];
188→
189→      const lastMessages = db.prepare(
190→        `SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
191→         FROM messages WHERE session_id = ? ORDER BY timestamp DESC LIMIT 20`
192→      ).all(sessionId) as SQLiteMessageRow[];
193→
194→      // Merge and deduplicate (for sessions with <= 40 messages, some overlap)
195→      const seenIds = new Set<string>();
196→      const messages: SQLiteMessageRow[] = [];
197→      for (const msg of [...firstMessages, ...lastMessages.reverse()]) {
198→        if (!seenIds.has(msg.id)) {
199→          seenIds.add(msg.id);
200→          messages.push(msg);
201→        }
202→      }
203→
204→      const result = await extractFacetsOnly(session, messages, { signal: abortSignal });
205→      if (result.success) {
206→        completed++;
207→      } else {
208→        failed++;
209→      }
210→
211→      await stream.writeSSE({
212→        event: 'progress',
213→        data: JSON.stringify({
214→          completed,
215→          failed,
216→          total,
217→          currentSessionId: sessionId,
218→          ...(result.success ? {} : { error: result.error }),
219→        }),
220→      });
221→    }
222→
223→    await stream.writeSSE({
224→      event: 'complete',
225→      data: JSON.stringify({ completed, failed, total }),
226→    });
227→  });
228→});
229→
230→export default app;
