  1→import type Database from 'better-sqlite3';
  2→import { SCHEMA_SQL, CURRENT_SCHEMA_VERSION } from './schema.js';
  3→
  4→/**
  5→ * Apply schema migrations to the database.
  6→ * Called once on startup before any reads or writes.
  7→ *
  8→ * Version 1: Initial schema (projects, sessions, messages, insights, usage_stats)
  9→ * Version 2: Add compound index on insights(confidence DESC, timestamp DESC) for depth-ordered export queries
 10→ * Version 3: Add session_facets table for cross-session analysis
 11→ * Version 4: Add reflect_snapshots table for caching LLM-generated synthesis results
 12→ * Version 5: Add deleted_at column to sessions for soft-delete (user-initiated hide)
 13→ */
 14→export function runMigrations(db: Database.Database): void {
 15→  // Create schema_version table first if it doesn't exist.
 16→  // This table is created inline (not via SCHEMA_SQL) so migrations can check it.
 17→  db.exec(`
 18→    CREATE TABLE IF NOT EXISTS schema_version (
 19→      version    INTEGER PRIMARY KEY,
 20→      applied_at TEXT NOT NULL DEFAULT (datetime('now'))
 21→    );
 22→  `);
 23→
 24→  const currentVersion = getCurrentVersion(db);
 25→
 26→  if (currentVersion < 1) {
 27→    applyV1(db);
 28→  }
 29→
 30→  if (currentVersion < 2) {
 31→    applyV2(db);
 32→  }
 33→
 34→  if (currentVersion < 3) {
 35→    applyV3(db);
 36→  }
 37→
 38→  if (currentVersion < 4) {
 39→    applyV4(db);
 40→  }
 41→
 42→  if (currentVersion < 5) {
 43→    applyV5(db);
 44→  }
 45→}
 46→
 47→function getCurrentVersion(db: Database.Database): number {
 48→  const row = db.prepare('SELECT MAX(version) as v FROM schema_version').get() as { v: number | null };
 49→  return row.v ?? 0;
 50→}
 51→
 52→function applyV1(db: Database.Database): void {
 53→  db.exec(SCHEMA_SQL);
 54→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(1);
 55→}
 56→
 57→function applyV2(db: Database.Database): void {
 58→  db.exec(`CREATE INDEX IF NOT EXISTS idx_insights_confidence_timestamp ON insights(confidence DESC, timestamp DESC)`);
 59→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(2);
 60→}
 61→
 62→function applyV3(db: Database.Database): void {
 63→  db.exec(`
 64→    CREATE TABLE IF NOT EXISTS session_facets (
 65→      session_id              TEXT PRIMARY KEY REFERENCES sessions(id),
 66→      outcome_satisfaction    TEXT NOT NULL,
 67→      workflow_pattern        TEXT,
 68→      had_course_correction   INTEGER NOT NULL DEFAULT 0,
 69→      course_correction_reason TEXT,
 70→      iteration_count         INTEGER NOT NULL DEFAULT 0,
 71→      friction_points         TEXT,
 72→      effective_patterns      TEXT,
 73→      extracted_at            TEXT NOT NULL DEFAULT (datetime('now')),
 74→      analysis_version        TEXT NOT NULL DEFAULT '1.0.0'
 75→    );
 76→
 77→    CREATE INDEX IF NOT EXISTS idx_facets_outcome ON session_facets(outcome_satisfaction);
 78→    CREATE INDEX IF NOT EXISTS idx_facets_workflow ON session_facets(workflow_pattern);
 79→  `);
 80→
 81→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(3);
 82→}
 83→
 84→function applyV4(db: Database.Database): void {
 85→  db.exec(`
 86→    CREATE TABLE IF NOT EXISTS reflect_snapshots (
 87→      period        TEXT NOT NULL,
 88→      project_id    TEXT NOT NULL DEFAULT '__all__',
 89→      results_json  TEXT NOT NULL,
 90→      generated_at  TEXT NOT NULL,
 91→      window_start  TEXT,
 92→      window_end    TEXT NOT NULL,
 93→      session_count INTEGER NOT NULL,
 94→      facet_count   INTEGER NOT NULL,
 95→      PRIMARY KEY (period, project_id)
 96→    );
 97→  `);
 98→
 99→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(4);
100→}
101→
102→function applyV5(db: Database.Database): void {
103→  db.exec(`ALTER TABLE sessions ADD COLUMN deleted_at TEXT`);
104→  db.exec(`CREATE INDEX IF NOT EXISTS idx_sessions_deleted_at ON sessions(deleted_at)`);
105→  db.prepare('INSERT OR IGNORE INTO schema_version (version) VALUES (?)').run(5);
106→}
