 1→import { parseJsonField } from '@/lib/types';
 2→import type { Insight } from '@/lib/types';
 3→
 4→/**
 5→ * Union-Find with iterative path compression.
 6→ * Groups insights that share linked_insight_ids.
 7→ */
 8→function find(parent: Map<string, string>, id: string): string {
 9→  if (!parent.has(id)) parent.set(id, id);
10→  let root = id;
11→  while (parent.get(root) !== root) {
12→    root = parent.get(root)!;
13→  }
14→  // Path compression
15→  let current = id;
16→  while (current !== root) {
17→    const next = parent.get(current)!;
18→    parent.set(current, root);
19→    current = next;
20→  }
21→  return root;
22→}
23→
24→function union(parent: Map<string, string>, a: string, b: string) {
25→  const ra = find(parent, a);
26→  const rb = find(parent, b);
27→  if (ra !== rb) parent.set(ra, rb);
28→}
29→
30→export function buildPatternGroups(insights: Insight[]): Map<string, Set<string>> {
31→  const linkedToInsights = new Map<string, Set<string>>();
32→  for (const insight of insights) {
33→    const linkedIds = insight.linked_insight_ids
34→      ? parseJsonField<string[]>(insight.linked_insight_ids, [])
35→      : [];
36→    for (const linkedId of linkedIds) {
37→      const set = linkedToInsights.get(linkedId) || new Set();
38→      set.add(insight.id);
39→      linkedToInsights.set(linkedId, set);
40→    }
41→  }
42→
43→  const parent = new Map<string, string>();
44→  for (const [, insightIds] of linkedToInsights) {
45→    const arr = [...insightIds];
46→    for (let i = 1; i < arr.length; i++) {
47→      union(parent, arr[0], arr[i]);
48→    }
49→  }
50→
51→  const groups = new Map<string, Set<string>>();
52→  for (const [, insightIds] of linkedToInsights) {
53→    for (const id of insightIds) {
54→      const root = find(parent, id);
55→      const set = groups.get(root) || new Set();
56→      set.add(id);
57→      groups.set(root, set);
58→    }
59→  }
60→
61→  return groups;
62→}
