 10→interface RecurringPatternsSectionProps {
 11→  insights: Insight[];
 12→}
 13→
 14→interface PatternGroup {
 15→  key: string;
 16→  title: string;
 17→  type: string;
 18→  count: number;
 19→  projects: string[];
 20→  lastSeen: string;
 21→  insightIds: Set<string>;
 22→}
 23→
 24→export function RecurringPatternsSection({ insights }: RecurringPatternsSectionProps) {
 25→  const patterns = useMemo((): PatternGroup[] => {
 26→    const insightMap = new Map<string, Insight>();
 27→    for (const insight of insights) {
 28→      insightMap.set(insight.id, insight);
 29→    }
 30→
 31→    const groups = buildPatternGroups(insights);
 32→
 33→    // Filter to groups with 2+ insights and build PatternGroup objects
 34→    const result: PatternGroup[] = [];
 35→    for (const [key, ids] of groups) {
 36→      if (ids.size < 2) continue;
 37→
 38→      const groupInsights = [...ids]
 39→        .map((id) => insightMap.get(id))
 40→        .filter((i): i is Insight => !!i);
 41→
 42→      if (groupInsights.length < 2) continue;
 43→
 44→      // Most common type in group
 45→      const typeCounts = new Map<string, number>();
 46→      for (const i of groupInsights) {
 47→        typeCounts.set(i.type, (typeCounts.get(i.type) || 0) + 1);
 48→      }
 49→      const dominantType = [...typeCounts.entries()].sort((a, b) => b[1] - a[1])[0][0];
 50→
 51→      const projects = [...new Set(groupInsights.map((i) => i.project_name))];
 52→      const lastSeen = groupInsights
 53→        .map((i) => i.created_at)
 54→        .sort()
 55→        .pop()!;
 56→
 57→      result.push({
 58→        key,
 59→        title: groupInsights[0].title,
 60→        type: dominantType,
 61→        count: groupInsights.length,
 62→        projects,
 63→        lastSeen,
 64→        insightIds: ids,
 65→      });
 66→    }
 67→
 68→    return result.sort((a, b) => b.count - a.count);
 69→  }, [insights]);
 70→
 71→  if (patterns.length === 0) return null;
 72→
 73→  return (
 74→    <div>
 75→      <div className="flex items-center gap-2 mb-3">
 76→        <Repeat2 className="h-4 w-4 text-amber-500" />
 77→        <h2 className="text-sm font-medium">Recurring Patterns</h2>
 78→        <Badge variant="secondary" className="text-xs">
 79→          {patterns.length}
 80→        </Badge>
 81→      </div>
 82→      <div className="grid gap-3 md:grid-cols-2 lg:grid-cols-3">
 83→        {patterns.map((pattern) => (
 84→          <Link
 85→            key={pattern.key}
 86→            to={`/insights?pattern=${pattern.key}`}
 87→            className="block rounded-lg border p-3 hover:bg-accent/40 transition-colors space-y-1.5"
 88→          >
 89→            <div className="flex items-start justify-between gap-2">
 90→              <p className="text-sm font-medium line-clamp-2">{pattern.title}</p>
 91→              <Badge variant="secondary" className="bg-amber-500/10 text-amber-600 border-amber-500/20 shrink-0">
 92→                {pattern.count}x
 93→              </Badge>
 94→            </div>
 95→            <div className="flex items-center gap-2 text-xs text-muted-foreground flex-wrap">
 96→              <span>{INSIGHT_TYPE_LABELS[pattern.type as InsightType] || pattern.type}</span>
 97→              <span>--</span>
 98→              <span className="truncate">{pattern.projects.join(', ')}</span>
 99→            </div>
100→            <p className="text-xs text-muted-foreground">
101→              Last seen {formatDistanceToNow(new Date(pattern.lastSeen), { addSuffix: true })}
102→            </p>
103→          </Link>
104→        ))}
105→      </div>
106→    </div>
107→  );
108→}
