 2→// Clusters similar free-form friction categories to canonical ones during aggregation.
 3→
 4→import { CANONICAL_FRICTION_CATEGORIES } from './prompts.js';
 5→
 6→// Explicit alias map for clustering emergent category variants.
 7→// Targets don't need to be in CANONICAL_FRICTION_CATEGORIES —
 8→// this clusters semantically-equivalent novel categories together.
 9→// Insert alias lookup runs AFTER exact canonical match but BEFORE Levenshtein,
10→// so well-known emergent variants are clustered deterministically.
11→const FRICTION_ALIASES: Record<string, string> = {
12→  // agent orchestration variants → cluster under one emergent name
13→  'agent-lifecycle-issue': 'agent-orchestration-failure',
14→  'agent-communication-failure': 'agent-orchestration-failure',
15→  'agent-communication-breakdown': 'agent-orchestration-failure',
16→  'agent-lifecycle-management': 'agent-orchestration-failure',
17→  'agent-shutdown-failure': 'agent-orchestration-failure',
18→  // rate limit variants → cluster under one emergent name
19→  'api-rate-limit': 'rate-limit-hit',
20→  'rate-limiting': 'rate-limit-hit',
21→  'rate-limited': 'rate-limit-hit',
22→};
23→
24→/** Standard Levenshtein distance between two strings */
25→function levenshtein(a: string, b: string): number {
26→  const m = a.length;
27→  const n = b.length;
28→  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0) as number[]);
29→
30→  for (let i = 0; i <= m; i++) dp[i][0] = i;
31→  for (let j = 0; j <= n; j++) dp[0][j] = j;
32→
33→  for (let i = 1; i <= m; i++) {
34→    for (let j = 1; j <= n; j++) {
35→      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
36→      dp[i][j] = Math.min(
37→        dp[i - 1][j] + 1,
38→        dp[i][j - 1] + 1,
39→        dp[i - 1][j - 1] + cost
40→      );
41→    }
42→  }
43→
44→  return dp[m][n];
45→}
46→
47→/**
48→ * Normalize a friction category to the closest canonical category.
49→ * Returns the original category if no close match is found.
50→ *
51→ * Matching rules (in order):
52→ * 1. Exact match against canonical list → return as-is
53→ * 1.5. Explicit alias match → return alias target (may be non-canonical)
54→ * 2. Levenshtein distance <= 2 → return canonical match
55→ * 3. Substring match (category contains canonical or vice versa) → return canonical
56→ * 4. No match → return original (novel category)
57→ *
58→ * Note: alias targets in FRICTION_ALIASES bypass the canonical check intentionally.
59→ * e.g., "agent-orchestration-failure" is not canonical but is a valid cluster target.
60→ */
61→export function normalizeFrictionCategory(category: string): string {
62→  const lower = category.toLowerCase();
63→
64→  // 1. Exact match
65→  for (const canonical of CANONICAL_FRICTION_CATEGORIES) {
66→    if (lower === canonical) return canonical;
67→  }
68→
69→  // 1.5. Explicit alias match — clusters emergent category variants deterministically.
70→  // Alias targets bypass further normalization; they are returned as-is even if
71→  // they are not in CANONICAL_FRICTION_CATEGORIES.
72→  if (FRICTION_ALIASES[lower]) return FRICTION_ALIASES[lower];
73→
74→  // 2. Levenshtein distance <= 2
75→  let bestMatch: string | null = null;
76→  let bestDistance = Infinity;
77→  for (const canonical of CANONICAL_FRICTION_CATEGORIES) {
78→    const dist = levenshtein(lower, canonical);
79→    if (dist <= 2 && dist < bestDistance) {
80→      bestDistance = dist;
81→      bestMatch = canonical;
82→    }
83→  }
84→  if (bestMatch) return bestMatch;
85→
86→  // 3. Substring match — only if the shorter string is a significant portion of the longer
87→  // to avoid false positives like "type" matching "type-error"
88→  for (const canonical of CANONICAL_FRICTION_CATEGORIES) {
89→    const shorter = lower.length < canonical.length ? lower : canonical;
90→    const longer = lower.length < canonical.length ? canonical : lower;
91→    if (shorter.length >= 5 && shorter.length / longer.length >= 0.5 && longer.includes(shorter)) {
92→      return canonical;
93→    }
94→  }
95→
96→  // 4. No match — novel category
97→  return category;
98→}
