356→export function extractJsonPayload(response: string): string | null {
357→  const tagged = response.match(/<json>\s*([\s\S]*?)\s*<\/json>/i);
358→  if (tagged?.[1]) return tagged[1].trim();
359→  const jsonMatch = response.match(/\{[\s\S]*\}/);
360→  return jsonMatch ? jsonMatch[0] : null;
361→}
