363→/**
364→ * Parse the LLM response into structured insights.
365→ */
366→export function parseAnalysisResponse(response: string): ParseResult<AnalysisResponse> {
367→  const response_length = response.length;
368→
369→  const preview = buildResponsePreview(response);
370→
371→  const jsonPayload = extractJsonPayload(response);
372→  if (!jsonPayload) {
373→    console.error('No JSON found in analysis response');
374→    return {
375→      success: false,
376→      error: { error_type: 'no_json_found', error_message: 'No JSON found in analysis response', response_length, response_preview: preview },
377→    };
378→  }
379→
380→  let parsed: AnalysisResponse;
381→  try {
382→    parsed = JSON.parse(jsonPayload) as AnalysisResponse;
383→  } catch {
384→    // Attempt repair — handles trailing commas, unclosed braces, truncated output
385→    try {
386→      parsed = JSON.parse(jsonrepair(jsonPayload)) as AnalysisResponse;
387→    } catch (err) {
388→      const msg = err instanceof Error ? err.message : String(err);
389→      console.error('Failed to parse analysis response (after jsonrepair):', err);
390→      return {
391→        success: false,
392→        error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
393→      };
394→    }
395→  }
396→
397→  if (!parsed.summary || typeof parsed.summary.title !== 'string') {
398→    console.error('Invalid analysis response structure');
399→    return {
400→      success: false,
401→      error: { error_type: 'invalid_structure', error_message: 'Missing or invalid summary field', response_length, response_preview: preview },
402→    };
403→  }
404→
405→  parsed.decisions = parsed.decisions || [];
406→  parsed.learnings = parsed.learnings || [];
407→
408→  // Validate session_character — drop if not a recognized value
409→  if (parsed.session_character && !VALID_SESSION_CHARACTERS.has(parsed.session_character)) {
410→    parsed.session_character = undefined;
411→  }
412→
413→  // Observability: warn when LLM still uses "tooling-limitation".
414→  // Monitors whether FRICTION_CLASSIFICATION_GUIDANCE is working.
415→  // Remove after confirming classification quality over ~20 new sessions.
416→  if (parsed.facets?.friction_points?.some(fp => fp.category === 'tooling-limitation')) {
417→    console.warn('[friction-monitor] LLM classified friction as "tooling-limitation" — verify this is a genuine tool limitation, not an agent/rate-limit/approach issue');
418→  }
419→
420→  return { success: true, data: parsed };
421→}
