600→export interface SessionTrait {
601→  trait: 'context_drift' | 'objective_bloat' | 'late_context' | 'no_planning' | 'good_structure';
602→  severity: 'high' | 'medium' | 'low';
603→  description: string;
604→  evidence?: string;
605→  suggestion?: string;
606→}
