608→export interface PromptQualityResponse {
609→  efficiencyScore: number;
610→  potentialMessageReduction: number;
611→  overallAssessment: string;
612→  wastedTurns: WastedTurn[];
613→  antiPatterns: AntiPattern[];
614→  sessionTraits: SessionTrait[];
615→  tips: string[];
