618→export function parsePromptQualityResponse(response: string): ParseResult<PromptQualityResponse> {
619→  const response_length = response.length;
620→
621→  const preview = buildResponsePreview(response);
622→
623→  const jsonPayload = extractJsonPayload(response);
624→  if (!jsonPayload) {
625→    console.error('No JSON found in prompt quality response');
626→    return {
627→      success: false,
628→      error: { error_type: 'no_json_found', error_message: 'No JSON found in prompt quality response', response_length, response_preview: preview },
629→    };
630→  }
631→
632→  let parsed: PromptQualityResponse;
633→  try {
634→    parsed = JSON.parse(jsonPayload) as PromptQualityResponse;
635→  } catch {
636→    try {
637→      parsed = JSON.parse(jsonrepair(jsonPayload)) as PromptQualityResponse;
638→    } catch (err) {
639→      const msg = err instanceof Error ? err.message : String(err);
640→      console.error('Failed to parse prompt quality response (after jsonrepair):', err);
641→      return {
642→        success: false,
643→        error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
644→      };
645→    }
646→  }
647→
648→  if (typeof parsed.efficiencyScore !== 'number') {
649→    console.error('Invalid prompt quality response: missing efficiencyScore');
650→    return {
651→      success: false,
652→      error: { error_type: 'invalid_structure', error_message: 'Missing or invalid efficiencyScore field', response_length, response_preview: preview },
653→    };
654→  }
655→
656→  parsed.efficiencyScore = Math.max(0, Math.min(100, Math.round(parsed.efficiencyScore)));
657→  parsed.potentialMessageReduction = parsed.potentialMessageReduction || 0;
658→  parsed.overallAssessment = parsed.overallAssessment || '';
659→  parsed.wastedTurns = parsed.wastedTurns || [];
660→  parsed.antiPatterns = parsed.antiPatterns || [];
661→  parsed.sessionTraits = parsed.sessionTraits || [];
662→  parsed.tips = parsed.tips || [];
663→
664→  return { success: true, data: parsed };
665→}
