 54→  avg_confidence: number;
 55→}
 56→
 57→export interface RateLimitInfo {
 58→  count: number;
 59→  sessionsAffected: number;
 60→  examples: string[];
 61→}
 62→
 63→export interface AggregatedData {
 64→  frictionCategories: AggregatedFrictionCategory[];
 65→  effectivePatterns: AggregatedEffectivePattern[];
 66→  outcomeDistribution: Record<string, number>;
 67→  workflowDistribution: Record<string, number>;
 68→  characterDistribution: Record<string, number>;
 69→  totalSessions: number;
 70→  frictionTotal: number;
 71→  totalAllSessions: number;  // all sessions in scope (not just those with facets)
 72→  rateLimitInfo: RateLimitInfo | null;
 73→  streak: number;            // consecutive days with at least one session (ignores period filter)
