 72→// GET /api/facets/missing
 73→// Returns session IDs that have insights but no session_facets row.
 74→// Used by CLI `reflect backfill` and dashboard facet status indicators.
 75→app.get('/missing', (c) => {
 76→  const db = getDb();
 77→  const period = c.req.query('period') || 'all';
 78→  const project = c.req.query('project');
 79→  const source = c.req.query('source');
 80→
 81→  // buildWhereClause can't be used here — it generates "WHERE ..." prefix,
 82→  // but this query already needs "WHERE sf.session_id IS NULL".
 83→  // Build conditions inline instead.
 84→  const conditions: string[] = ['sf.session_id IS NULL', 's.deleted_at IS NULL'];
 85→  const params: (string | number)[] = [];
 86→
 87→  if (period !== 'all') {
 88→    const now = new Date();
 89→    const days = period === '7d' ? 7 : period === '30d' ? 30 : period === '90d' ? 90 : 0;
 90→    if (days > 0) {
 91→      conditions.push('s.started_at >= ?');
 92→      params.push(new Date(now.getTime() - days * 86400000).toISOString());
 93→    }
 94→  }
 95→  if (project) {
 96→    conditions.push('s.project_id = ?');
 97→    params.push(project);
 98→  }
 99→  if (source) {
100→    conditions.push('s.source_tool = ?');
101→    params.push(source);
102→  }
103→
104→  const where = `WHERE ${conditions.join(' AND ')}`;
105→
106→  const rows = db.prepare(`
107→    SELECT DISTINCT i.session_id
108→    FROM insights i
109→    JOIN sessions s ON i.session_id = s.id
110→    LEFT JOIN session_facets sf ON i.session_id = sf.session_id
111→    ${where}
112→  `).all(...params) as Array<{ session_id: string }>;
113→
114→  const sessionIds = rows.map(r => r.session_id);
115→  return c.json({ sessionIds, count: sessionIds.length });
116→});
