118→// POST /api/facets/backfill
119→// Body: { sessionIds: string[] }
120→// Streams progress as facets are extracted one-by-one for sessions that lack them.
121→// Uses extractFacetsOnly (lightweight prompt: summary + first/last 20 messages).
122→app.post('/backfill', async (c) => {
123→  if (!isLLMConfigured()) {
124→    return c.json({ error: 'LLM not configured.' }, 400);
125→  }
126→
127→  const body = await c.req.json<{ sessionIds?: string[] }>();
128→  if (!body.sessionIds || !Array.isArray(body.sessionIds) || body.sessionIds.length === 0) {
129→    return c.json({ error: 'sessionIds array required' }, 400);
130→  }
131→  if (body.sessionIds.length > MAX_BACKFILL_SESSIONS) {
132→    return c.json({ error: `Maximum ${MAX_BACKFILL_SESSIONS} sessions per backfill request` }, 400);
133→  }
134→
135→  const db = getDb();
136→
137→  return streamSSE(c, async (stream) => {
138→    const abortSignal = c.req.raw.signal;
139→    let completed = 0;
140→    let failed = 0;
141→    const total = body.sessionIds!.length;
142→
143→    for (const sessionId of body.sessionIds!) {
144→      if (abortSignal.aborted) break;
145→
146→      const session = db.prepare(
147→        `SELECT id, project_id, project_name, project_path, summary, ended_at
148→         FROM sessions WHERE id = ? AND deleted_at IS NULL`
149→      ).get(sessionId) as SessionData | undefined;
150→
151→      if (!session) {
152→        failed++;
153→        await stream.writeSSE({
154→          event: 'progress',
155→          data: JSON.stringify({
156→            completed,
157→            failed,
158→            total,
159→            currentSessionId: sessionId,
160→          }),
161→        });
162→        continue;
163→      }
164→
165→      // Skip sessions that already have facets (race condition guard)
166→      const existingFacet = db.prepare(
167→        'SELECT 1 FROM session_facets WHERE session_id = ?'
168→      ).get(sessionId);
169→      if (existingFacet) {
170→        completed++;
171→        await stream.writeSSE({
172→          event: 'progress',
173→          data: JSON.stringify({
174→            completed,
175→            failed,
176→            total,
177→            currentSessionId: sessionId,
178→          }),
179→        });
180→        continue;
181→      }
182→
183→      // Only load first 20 and last 20 messages for facet extraction
184→      const firstMessages = db.prepare(
185→        `SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
186→         FROM messages WHERE session_id = ? ORDER BY timestamp ASC LIMIT 20`
187→      ).all(sessionId) as SQLiteMessageRow[];
188→
189→      const lastMessages = db.prepare(
190→        `SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
191→         FROM messages WHERE session_id = ? ORDER BY timestamp DESC LIMIT 20`
192→      ).all(sessionId) as SQLiteMessageRow[];
193→
194→      // Merge and deduplicate (for sessions with <= 40 messages, some overlap)
195→      const seenIds = new Set<string>();
196→      const messages: SQLiteMessageRow[] = [];
197→      for (const msg of [...firstMessages, ...lastMessages.reverse()]) {
198→        if (!seenIds.has(msg.id)) {
199→          seenIds.add(msg.id);
200→          messages.push(msg);
201→        }
202→      }
203→
204→      const result = await extractFacetsOnly(session, messages, { signal: abortSignal });
205→      if (result.success) {
206→        completed++;
207→      } else {
208→        failed++;
209→      }
210→
211→      await stream.writeSSE({
212→        event: 'progress',
213→        data: JSON.stringify({
214→          completed,
215→          failed,
216→          total,
217→          currentSessionId: sessionId,
218→          ...(result.success ? {} : { error: result.error }),
219→        }),
220→      });
221→    }
222→
223→    await stream.writeSSE({
224→      event: 'complete',
225→      data: JSON.stringify({ completed, failed, total }),
226→    });
227→  });
228→});
