388→export interface RecurringInsightResult {
389→  success: boolean;
390→  groups: RecurringInsightGroup[];
391→  updatedCount: number;
392→  error?: string;
393→  usage?: {
394→    inputTokens: number;
395→    outputTokens: number;
396→  };
