538→
539→function chunkMessages(
540→  messages: SQLiteMessageRow[],
541→  estimateTokens: (text: string) => number
542→): SQLiteMessageRow[][] {
543→  const chunks: SQLiteMessageRow[][] = [];
544→  let currentChunk: SQLiteMessageRow[] = [];
545→  let currentTokens = 0;
546→  const chunkLimit = MAX_INPUT_TOKENS * 0.8;
547→
548→  for (const message of messages) {
549→    let toolResults: Array<{ output?: string }> = [];
550→    try {
551→      toolResults = message.tool_results ? JSON.parse(message.tool_results) as Array<{ output?: string }> : [];
552→    } catch {
553→      toolResults = [];
554→    }
555→
556→    const messageText = [
557→      message.content,
558→      message.thinking?.slice(0, 1000) ?? '',
559→      ...toolResults.map(r => (r.output || '').slice(0, 500)),
560→    ].join(' ');
561→    const messageTokens = estimateTokens(messageText);
562→
563→    if (currentTokens + messageTokens > chunkLimit && currentChunk.length > 0) {
564→      chunks.push(currentChunk);
565→      currentChunk = [];
566→      currentTokens = 0;
567→    }
568→
569→    currentChunk.push(message);
570→    currentTokens += messageTokens;
571→  }
572→
573→  if (currentChunk.length > 0) {
574→    chunks.push(currentChunk);
575→  }
576→
577→  return chunks;
578→}
