847→/**
848→ * Extract facets only for a session that already has insights (backfill).
849→ * Uses lightweight prompt with summary + first/last 20 messages.
850→ */
851→export async function extractFacetsOnly(
852→  session: SessionData,
853→  messages: SQLiteMessageRow[],
854→  options?: { signal?: AbortSignal }
855→): Promise<{ success: boolean; error?: string }> {
856→  if (!isLLMConfigured()) {
857→    return { success: false, error: 'LLM not configured.' };
858→  }
859→
860→  if (messages.length === 0) {
861→    return { success: false, error: 'No messages found.' };
862→  }
863→
864→  try {
865→    const client = createLLMClient();
866→    const firstMsgs = formatMessagesForAnalysis(messages.slice(0, 20));
867→    const lastMsgs = formatMessagesForAnalysis(messages.slice(-20));
868→    const prompt = generateFacetOnlyPrompt(
869→      session.project_name,
870→      session.summary,
871→      firstMsgs,
872→      lastMsgs
873→    );
874→
875→    const response = await client.chat([
876→      { role: 'system', content: FACET_ONLY_SYSTEM_PROMPT },
877→      { role: 'user', content: prompt },
878→    ], { signal: options?.signal });
879→
880→    const jsonPayload = extractJsonPayload(response.content);
881→    if (!jsonPayload) {
882→      return { success: false, error: 'No JSON in facet response.' };
883→    }
884→
885→    let facets: AnalysisResponse['facets'];
886→    try {
887→      facets = JSON.parse(jsonPayload);
888→    } catch {
889→      facets = JSON.parse(jsonrepair(jsonPayload));
890→    }
891→
892→    if (facets) {
893→      saveFacetsToDb(session.id, facets, ANALYSIS_VERSION);
894→    }
895→
896→    return { success: true };
897→  } catch (error) {
898→    if (error instanceof Error && error.name === 'AbortError') {
899→      return { success: false, error: 'Cancelled' };
900→    }
901→    return {
902→      success: false,
903→      error: error instanceof Error ? error.message : 'Facet extraction failed',
904→    };
905→  }
906→}
