  1→// Shared aggregation logic for facets and reflect routes.
  2→// Extracted to avoid ~150 lines of duplication between the two routes.
  3→
  4→import { getDb } from '@code-insights/cli/db/client';
  5→import { normalizeFrictionCategory } from '../llm/friction-normalize.js';
  6→
  7→export function buildPeriodFilter(period: string): string | null {
  8→  const now = new Date();
  9→  if (period === '7d') return new Date(now.getTime() - 7 * 86400000).toISOString();
 10→  if (period === '30d') return new Date(now.getTime() - 30 * 86400000).toISOString();
 11→  if (period === '90d') return new Date(now.getTime() - 90 * 86400000).toISOString();
 12→  return null; // 'all'
 13→}
 14→
 15→export function buildWhereClause(
 16→  period: string,
 17→  project?: string,
 18→  source?: string
 19→): { where: string; params: (string | number)[] } {
 20→  // Always exclude soft-deleted sessions from aggregations
 21→  const conditions: string[] = ['s.deleted_at IS NULL'];
 22→  const params: (string | number)[] = [];
 23→
 24→  const periodStart = buildPeriodFilter(period);
 25→  if (periodStart) {
 26→    conditions.push('s.started_at >= ?');
 27→    params.push(periodStart);
 28→  }
 29→  if (project) {
 30→    conditions.push('s.project_id = ?');
 31→    params.push(project);
 32→  }
 33→  if (source) {
 34→    conditions.push('s.source_tool = ?');
 35→    params.push(source);
 36→  }
 37→
 38→  return {
 39→    where: `WHERE ${conditions.join(' AND ')}`,
 40→    params,
 41→  };
 42→}
 43→
 44→export interface AggregatedFrictionCategory {
 45→  category: string;
 46→  count: number;
 47→  avg_severity: number;
 48→  examples: string[];
 49→}
 50→
 51→export interface AggregatedEffectivePattern {
 52→  description: string;
 53→  frequency: number;
 54→  avg_confidence: number;
 55→}
 56→
 57→export interface RateLimitInfo {
 58→  count: number;
 59→  sessionsAffected: number;
 60→  examples: string[];
 61→}
 62→
 63→export interface AggregatedData {
 64→  frictionCategories: AggregatedFrictionCategory[];
 65→  effectivePatterns: AggregatedEffectivePattern[];
 66→  outcomeDistribution: Record<string, number>;
 67→  workflowDistribution: Record<string, number>;
 68→  characterDistribution: Record<string, number>;
 69→  totalSessions: number;
 70→  frictionTotal: number;
 71→  totalAllSessions: number;  // all sessions in scope (not just those with facets)
 72→  rateLimitInfo: RateLimitInfo | null;
 73→  streak: number;            // consecutive days with at least one session (ignores period filter)
 74→  sourceToolCount: number;   // distinct AI tools used within the scope
 75→}
 76→
 77→/**
 78→ * Run all aggregation queries needed for facet analysis and synthesis.
 79→ * Aggregation is done in code (SQL), not by LLMs — LLMs synthesize, they don't count.
 80→ *
 81→ * project and source are passed separately so streak can build its own
 82→ * period-free where clause (streak measures continuity across all time).
 83→ */
 84→export function getAggregatedData(
 85→  db: ReturnType<typeof getDb>,
 86→  where: string,
 87→  params: (string | number)[],
 88→  project?: string,
 89→  source?: string
 90→): AggregatedData {
 91→  const hasWhere = where.length > 0;
 92→  const extraPrefix = hasWhere ? 'AND' : 'WHERE';
 93→
 94→  const frictionCategories = db.prepare(`
 95→    SELECT
 96→      json_extract(je.value, '$.category') as category,
 97→      COUNT(*) as count,
 98→      AVG(CASE
 99→        WHEN json_extract(je.value, '$.severity') = 'high' THEN 3
100→        WHEN json_extract(je.value, '$.severity') = 'medium' THEN 2
101→        ELSE 1
102→      END) as avg_severity,
103→      json_group_array(json_extract(je.value, '$.description')) as examples,
104→      json_group_array(sf.session_id) as session_ids
105→    FROM session_facets sf
106→    JOIN sessions s ON sf.session_id = s.id
107→    CROSS JOIN json_each(sf.friction_points) je
108→    ${where}
109→    GROUP BY category
110→    ORDER BY count DESC, avg_severity DESC
111→  `).all(...params) as Array<{ category: string; count: number; avg_severity: number; examples: string; session_ids: string }>;
112→
113→  const effectivePatterns = db.prepare(`
114→    SELECT
115→      json_extract(je.value, '$.description') as description,
116→      COUNT(*) as frequency,
117→      AVG(json_extract(je.value, '$.confidence')) as avg_confidence
118→    FROM session_facets sf
119→    JOIN sessions s ON sf.session_id = s.id
120→    CROSS JOIN json_each(sf.effective_patterns) je
121→    ${where}
122→    GROUP BY description
123→    ORDER BY frequency DESC, avg_confidence DESC
124→  `).all(...params) as Array<{ description: string; frequency: number; avg_confidence: number }>;
125→
126→  const outcomeDistribution = db.prepare(`
127→    SELECT outcome_satisfaction, COUNT(*) as count
128→    FROM session_facets sf JOIN sessions s ON sf.session_id = s.id
129→    ${where}
130→    GROUP BY outcome_satisfaction
131→  `).all(...params) as Array<{ outcome_satisfaction: string; count: number }>;
132→
133→  const workflowDistribution = db.prepare(`
134→    SELECT workflow_pattern, COUNT(*) as count
135→    FROM session_facets sf JOIN sessions s ON sf.session_id = s.id
136→    ${where}
137→    ${extraPrefix} sf.workflow_pattern IS NOT NULL
138→    GROUP BY workflow_pattern
139→  `).all(...params) as Array<{ workflow_pattern: string; count: number }>;
140→
141→  const characterDistribution = db.prepare(`
142→    SELECT session_character, COUNT(*) as count
143→    FROM sessions s
144→    ${where}
145→    ${extraPrefix} s.session_character IS NOT NULL
146→    GROUP BY session_character
147→  `).all(...params) as Array<{ session_character: string; count: number }>;
148→
149→  const totalRow = db.prepare(
150→    `SELECT COUNT(*) as count FROM session_facets sf JOIN sessions s ON sf.session_id = s.id ${where}`
151→  ).get(...params) as { count: number };
152→
153→  const totalAllRow = db.prepare(
154→    `SELECT COUNT(*) as count FROM sessions s ${where}`
155→  ).get(...params) as { count: number };
156→
157→  // Parse examples and session_ids from json_group_array output, then normalize via alias + Levenshtein clustering
158→  const parsedFriction = frictionCategories.map(fc => ({
159→    ...fc,
160→    examples: JSON.parse(fc.examples) as string[],
161→    session_ids: JSON.parse(fc.session_ids) as string[],
162→  }));
163→
164→  const normalizedFriction = new Map<string, { count: number; total_severity: number; examples: string[]; session_ids: string[] }>();
165→  for (const fc of parsedFriction) {
166→    const normalized = normalizeFrictionCategory(fc.category);
167→    const existing = normalizedFriction.get(normalized);
168→    if (existing) {
169→      existing.count += fc.count;
170→      existing.total_severity += fc.avg_severity * fc.count;
171→      existing.examples.push(...fc.examples);
172→      existing.session_ids.push(...fc.session_ids);
173→    } else {
174→      normalizedFriction.set(normalized, {
175→        count: fc.count,
176→        total_severity: fc.avg_severity * fc.count,
177→        examples: [...fc.examples],
178→        session_ids: [...fc.session_ids],
179→      });
180→    }
181→  }
182→
183→  // Partition: separate rate-limit-hit entries from general friction.
184→  // Rate limits are a billing/plan constraint — surfaced as a usage insight, not friction.
185→  // The alias map already normalizes all rate limit variants to "rate-limit-hit".
186→  // A regex sweep catches creative LLM variants ("throttled-by-api", etc.) that bypass
187→  // both the alias map and Levenshtein clustering.
188→  const RATE_LIMIT_CATEGORY = 'rate-limit-hit';
189→  const RATE_LIMIT_REGEX = /rate.?limit|throttl/i;
190→  let rateLimitInfo: RateLimitInfo | null = null;
191→
192→  // Accumulated data for rateLimitInfo, merged from exact match + regex sweep
193→  let rateLimitCount = 0;
194→  let rateLimitSessionIds: string[] = [];
195→  let rateLimitExamples: string[] = [];
196→
197→  const rateLimitEntry = normalizedFriction.get(RATE_LIMIT_CATEGORY);
198→  if (rateLimitEntry) {
199→    rateLimitCount += rateLimitEntry.count;
200→    rateLimitSessionIds.push(...rateLimitEntry.session_ids);
201→    rateLimitExamples.push(...rateLimitEntry.examples);
202→    normalizedFriction.delete(RATE_LIMIT_CATEGORY);
203→  }
204→
205→  // Regex sweep over remaining entries to catch variants the alias map missed
206→  for (const [category, entry] of normalizedFriction) {
207→    if (RATE_LIMIT_REGEX.test(category)) {
208→      rateLimitCount += entry.count;
209→      rateLimitSessionIds.push(...entry.session_ids);
210→      rateLimitExamples.push(...entry.examples);
211→      normalizedFriction.delete(category);
212→    }
213→  }
214→
215→  if (rateLimitCount > 0) {
216→    const uniqueSessions = new Set(rateLimitSessionIds);
217→    rateLimitInfo = {
218→      count: rateLimitCount,
219→      sessionsAffected: uniqueSessions.size,
220→      examples: rateLimitExamples.slice(0, 3),
221→    };
222→  }
223→
224→  const mergedFriction = Array.from(normalizedFriction.entries())
225→    .map(([category, data]) => ({
226→      category,
227→      count: data.count,
228→      avg_severity: data.total_severity / data.count,
229→      examples: data.examples.slice(0, 10),
230→    }))
231→    .sort((a, b) => b.count - a.count || b.avg_severity - a.avg_severity);
232→
233→  // frictionTotal reflects only non-rate-limit friction (rate limits partitioned separately)
234→  const frictionTotal = mergedFriction.reduce((sum, fc) => sum + fc.count, 0);
235→
236→  // Count distinct source tools within scope (for hero card stat pill)
237→  const sourceToolRow = db.prepare(
238→    `SELECT COUNT(DISTINCT source_tool) as count FROM sessions s ${where}`
239→  ).get(...params) as { count: number };
240→
241→  // Streak: count consecutive days (backward from today) with at least one session.
242→  // Always uses all-time scope — filtering by period would cap streak at the window size.
243→  // Respects project and source filters since those are user-scope constraints.
244→  const { where: streakWhere, params: streakParams } = buildWhereClause('all', project, source);
245→  const sessionDates = db.prepare(
246→    `SELECT DISTINCT date(started_at) as session_date FROM sessions s ${streakWhere} ORDER BY session_date DESC`
247→  ).all(...streakParams) as Array<{ session_date: string }>;
248→
249→  // Compare dates as YYYY-MM-DD strings in UTC to match SQLite's date() output.
250→  // Using toISOString().slice(0,10) avoids local timezone shifting the day boundary.
251→  const todayUTC = new Date().toISOString().slice(0, 10);
252→  const yesterdayUTC = new Date(Date.now() - 86400000).toISOString().slice(0, 10);
253→
254→  let streak = 0;
255→  // baseline is the date we expect for the next streak entry.
256→  // Start at today; if first session is yesterday, reset baseline to yesterday so
257→  // the loop can continue counting backward from there correctly.
258→  let baseline: string | null = null;
259→
260→  for (const { session_date } of sessionDates) {
261→    if (baseline === null) {
262→      // First entry: must be today or yesterday to start an active streak
263→      if (session_date === todayUTC) {
264→        baseline = todayUTC;
265→      } else if (session_date === yesterdayUTC) {
266→        baseline = yesterdayUTC;
267→      } else {
268→        break; // Gap from today — no active streak
269→      }
270→      streak++;
271→    } else {
272→      // Subsequent entries: must be exactly one day before current baseline
273→      const prevDay: Date = new Date((baseline as string) + 'T00:00:00Z');
274→      prevDay.setUTCDate(prevDay.getUTCDate() - 1);
275→      const expectedPrev: string = prevDay.toISOString().slice(0, 10);
276→      if (session_date !== expectedPrev) break;
277→      baseline = expectedPrev;
278→      streak++;
279→    }
280→  }
281→
282→  return {
283→    frictionCategories: mergedFriction,
284→    effectivePatterns,
285→    outcomeDistribution: Object.fromEntries(outcomeDistribution.map(o => [o.outcome_satisfaction, o.count])),
286→    workflowDistribution: Object.fromEntries(workflowDistribution.map(w => [w.workflow_pattern, w.count])),
287→    characterDistribution: Object.fromEntries(characterDistribution.map(ch => [ch.session_character, ch.count])),
288→    totalSessions: totalRow.count,
289→    frictionTotal,
290→    totalAllSessions: totalAllRow.count,
291→    rateLimitInfo,
292→    streak,
293→    sourceToolCount: sourceToolRow.count,
294→  };
295→}
