  1→import { Hono } from 'hono';
  2→import { streamSSE } from 'hono/streaming';
  3→import { getDb } from '@code-insights/cli/db/client';
  4→import { jsonrepair } from 'jsonrepair';
  5→import { createLLMClient, isLLMConfigured } from '../llm/client.js';
  6→import { extractJsonPayload } from '../llm/prompts.js';
  7→import {
  8→  FRICTION_WINS_SYSTEM_PROMPT,
  9→  generateFrictionWinsPrompt,
 10→  RULES_SKILLS_SYSTEM_PROMPT,
 11→  generateRulesSkillsPrompt,
 12→  WORKING_STYLE_SYSTEM_PROMPT,
 13→  generateWorkingStylePrompt,
 14→} from '../llm/reflect-prompts.js';
 15→import { buildWhereClause, buildPeriodFilter, getAggregatedData } from './shared-aggregation.js';
 16→import type { ReflectSection } from '@code-insights/cli/types';
 17→
 18→const app = new Hono();
 19→
 20→const MIN_FACETS_FOR_REFLECT = 20;
 21→
 22→const ALL_SECTIONS: ReflectSection[] = ['friction-wins', 'rules-skills', 'working-style'];
 23→
 24→// Parse LLM JSON response wrapped in <json>...</json> tags with jsonrepair fallback.
 25→function parseLLMJson<T>(response: string): T | null {
 26→  const payload = extractJsonPayload(response);
 27→  if (!payload) return null;
 28→  try {
 29→    return JSON.parse(payload) as T;
 30→  } catch {
 31→    try {
 32→      return JSON.parse(jsonrepair(payload)) as T;
 33→    } catch {
 34→      return null;
 35→    }
 36→  }
 37→}
 38→
 39→// Detect the dominant source tool from the database to target artifact generation.
 40→function detectTargetTool(db: ReturnType<typeof getDb>): string {
 41→  const row = db.prepare(
 42→    `SELECT source_tool, COUNT(*) as count FROM sessions WHERE deleted_at IS NULL GROUP BY source_tool ORDER BY count DESC LIMIT 1`
 43→  ).get() as { source_tool: string; count: number } | undefined;
 44→  return row?.source_tool || 'claude-code';
 45→}
 46→
 47→// POST /api/reflect/generate
 48→// Body: { sections?: ReflectSection[], period?: string, project?: string, source?: string }
 49→// SSE endpoint: aggregates facets in code, then calls synthesis prompts for each section.
 50→// Streams progress events so the UI can show phase-by-phase progress.
 51→app.post('/generate', async (c) => {
 52→  if (!isLLMConfigured()) {
 53→    return c.json({ error: 'LLM not configured.' }, 400);
 54→  }
 55→
 56→  const body = await c.req.json<{
 57→    sections?: ReflectSection[];
 58→    period?: string;
 59→    project?: string;
 60→    source?: string;
 61→  }>();
 62→
 63→  const sections = body.sections && body.sections.length > 0 ? body.sections : ALL_SECTIONS;
 64→  const period = body.period || '30d';
 65→
 66→  const db = getDb();
 67→  const { where, params } = buildWhereClause(period, body.project, body.source);
 68→
 69→  return streamSSE(c, async (stream) => {
 70→    const abortSignal = c.req.raw.signal;
 71→
 72→    try {
 73→      await stream.writeSSE({
 74→        event: 'progress',
 75→        data: JSON.stringify({ phase: 'aggregating', message: 'Aggregating facets...' }),
 76→      });
 77→
 78→      const aggregated = getAggregatedData(db, where, params, body.project, body.source);
 79→
 80→      if (aggregated.totalSessions === 0) {
 81→        await stream.writeSSE({
 82→          event: 'error',
 83→          data: JSON.stringify({ error: 'No sessions with facets found. Run analysis first.' }),
 84→        });
 85→        return;
 86→      }
 87→
 88→      if (aggregated.totalSessions < MIN_FACETS_FOR_REFLECT) {
 89→        await stream.writeSSE({
 90→          event: 'error',
 91→          data: JSON.stringify({
 92→            error: `Need at least ${MIN_FACETS_FOR_REFLECT} analyzed sessions for meaningful pattern synthesis. Currently have ${aggregated.totalSessions}. Run session analysis on more sessions first.`,
 93→            code: 'INSUFFICIENT_FACETS',
 94→            current: aggregated.totalSessions,
 95→            required: MIN_FACETS_FOR_REFLECT,
 96→          }),
 97→        });
 98→        return;
 99→      }
100→
101→      const client = createLLMClient();
102→      const results: Record<string, unknown> = {};
103→      const targetTool = detectTargetTool(db);
104→
105→      for (const section of sections) {
106→        if (abortSignal.aborted) break;
107→
108→        await stream.writeSSE({
109→          event: 'progress',
110→          data: JSON.stringify({ phase: 'synthesizing', section, message: `Generating ${section}...` }),
111→        });
112→
113→        if (section === 'friction-wins') {
114→          const prompt = generateFrictionWinsPrompt({
115→            frictionCategories: aggregated.frictionCategories,
116→            effectivePatterns: aggregated.effectivePatterns,
117→            totalSessions: aggregated.totalSessions,
118→            period,
119→          });
120→          const response = await client.chat([
121→            { role: 'system', content: FRICTION_WINS_SYSTEM_PROMPT },
122→            { role: 'user', content: prompt },
123→          ], { signal: abortSignal });
124→          const parsed = parseLLMJson(response.content);
125→          results['friction-wins'] = {
126→            section: 'friction-wins',
127→            ...(parsed ?? {}),
128→            frictionCategories: aggregated.frictionCategories,
129→            effectivePatterns: aggregated.effectivePatterns,
130→            generatedAt: new Date().toISOString(),
131→          };
132→        } else if (section === 'rules-skills') {
133→          // Only include patterns with sufficient occurrence counts for actionable artifacts
134→          const recurringFriction = aggregated.frictionCategories.filter(fc => fc.count >= 3);
135→          const recurringPatterns = aggregated.effectivePatterns.filter(ep => ep.frequency >= 2);
136→          const prompt = generateRulesSkillsPrompt({
137→            recurringFriction,
138→            effectivePatterns: recurringPatterns,
139→            targetTool,
140→          });
141→          const response = await client.chat([
142→            { role: 'system', content: RULES_SKILLS_SYSTEM_PROMPT },
143→            { role: 'user', content: prompt },
144→          ], { signal: abortSignal });
145→          const parsed = parseLLMJson(response.content);
146→          results['rules-skills'] = {
147→            section: 'rules-skills',
148→            ...(parsed ?? {}),
149→            targetTool,
150→            generatedAt: new Date().toISOString(),
151→          };
152→        } else if (section === 'working-style') {
153→          const prompt = generateWorkingStylePrompt({
154→            workflowDistribution: aggregated.workflowDistribution,
155→            outcomeDistribution: aggregated.outcomeDistribution,
156→            characterDistribution: aggregated.characterDistribution,
157→            totalSessions: aggregated.totalSessions,
158→            period,
159→            frictionFrequency: aggregated.frictionTotal,
160→          });
161→          const response = await client.chat([
162→            { role: 'system', content: WORKING_STYLE_SYSTEM_PROMPT },
163→            { role: 'user', content: prompt },
164→          ], { signal: abortSignal });
165→          const parsed = parseLLMJson(response.content);
166→          // Sanitize tagline: must be a string ≤40 chars. Non-string LLM outputs
167→          // (object, array, number) are normalized to undefined so they don't
168→          // corrupt the snapshot blob stored in SQLite.
169→          const rawTagline = parsed && (parsed as Record<string, unknown>)['tagline'];
170→          const tagline = typeof rawTagline === 'string'
171→            ? rawTagline.slice(0, 40)
172→            : undefined;
173→          results['working-style'] = {
174→            section: 'working-style',
175→            ...(parsed ?? {}),
176→            tagline,
177→            workflowDistribution: aggregated.workflowDistribution,
178→            outcomeDistribution: aggregated.outcomeDistribution,
179→            characterDistribution: aggregated.characterDistribution,
180→            generatedAt: new Date().toISOString(),
181→          };
182→        }
183→      }
184→
185→      // Only save snapshot if the request was not aborted mid-generation.
186→      // Saving partial results would cause stale/incomplete data to auto-load on next visit.
187→      if (!c.req.raw.signal.aborted) {
188→        const windowEnd = new Date().toISOString();
189→        const windowStart = buildPeriodFilter(period);
190→        const projectKey = body.project || '__all__';
191→
192→        db.prepare(`
193→          INSERT INTO reflect_snapshots (period, project_id, results_json, generated_at, window_start, window_end, session_count, facet_count)
194→          VALUES (?, ?, ?, ?, ?, ?, ?, ?)
195→          ON CONFLICT(period, project_id) DO UPDATE SET
196→            results_json = excluded.results_json,
197→            generated_at = excluded.generated_at,
198→            window_start = excluded.window_start,
199→            window_end = excluded.window_end,
200→            session_count = excluded.session_count,
201→            facet_count = excluded.facet_count
202→        `).run(
203→          period,
204→          projectKey,
205→          JSON.stringify(results),
206→          windowEnd,
207→          windowStart,
208→          windowEnd,
209→          aggregated.totalSessions,
210→          aggregated.frictionTotal
211→        );
212→      }
213→
214→      await stream.writeSSE({
215→        event: 'complete',
216→        data: JSON.stringify({ results }),
217→      });
218→    } catch (err) {
219→      const message = err instanceof Error ? err.message : 'Unknown error';
220→      await stream.writeSSE({
221→        event: 'error',
222→        data: JSON.stringify({ error: message }),
223→      }).catch(() => {});
224→    }
225→  });
226→});
