228→// GET /api/reflect/results
229→// Returns raw aggregated facet data without LLM synthesis (fast, no cost).
230→// The full synthesized view requires POST /api/reflect/generate.
231→app.get('/results', (c) => {
232→  const db = getDb();
233→  const period = c.req.query('period') || '30d';
234→  const project = c.req.query('project');
235→  const source = c.req.query('source');
236→
237→  const { where, params } = buildWhereClause(period, project, source);
238→  const aggregated = getAggregatedData(db, where, params, project, source);
239→
240→  return c.json(aggregated);
241→});
