243→// GET /api/reflect/snapshot
244→// Returns cached reflect results for a given period/project combo.
245→app.get('/snapshot', (c) => {
246→  const db = getDb();
247→  const period = c.req.query('period') || '30d';
248→  const project = c.req.query('project') || '__all__';
249→
250→  const row = db.prepare(
251→    `SELECT * FROM reflect_snapshots WHERE period = ? AND project_id = ?`
252→  ).get(period, project) as {
253→    period: string;
254→    project_id: string;
255→    results_json: string;
256→    generated_at: string;
257→    window_start: string | null;
258→    window_end: string;
259→    session_count: number;
260→    facet_count: number;
261→  } | undefined;
262→
263→  if (!row) {
264→    return c.json({ snapshot: null });
265→  }
266→
267→  let results: unknown;
268→  try {
269→    results = JSON.parse(row.results_json);
270→  } catch {
271→    // Corrupted snapshot data — treat as if no snapshot exists
272→    return c.json({ snapshot: null });
273→  }
274→
275→  return c.json({
276→    snapshot: {
277→      period: row.period,
278→      projectId: row.project_id,
279→      results,
280→      generatedAt: row.generated_at,
281→      windowStart: row.window_start,
282→      windowEnd: row.window_end,
283→      sessionCount: row.session_count,
284→      facetCount: row.facet_count,
285→    },
286→  });
287→});
288→
289→export default app;
