 35→function formatRelativeDate(iso: string): string {
 36→  const diff = Date.now() - new Date(iso).getTime();
 37→  const mins = Math.max(0, Math.floor(diff / 60000));
 38→  if (mins < 1) return 'just now';
 39→  if (mins < 60) return `${mins}m ago`;
 40→  const hours = Math.floor(mins / 60);
 41→  if (hours < 24) return `${hours}h ago`;
 42→  const days = Math.floor(hours / 24);
 43→  return `${days}d ago`;
 44→}
 45→
 46→function formatShortDate(iso: string): string {
 47→  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
 48→}
