  1→// Core analysis engine — server-side.
  2→// Ported from web repo (src/lib/llm/analysis.ts) with SQLite persistence replacing Firestore.
  3→// Key differences from web repo:
  4→//   - Uses SQLiteMessageRow instead of web Message type
  5→//   - Writes insights directly to SQLite via getDb() (not Firestore)
  6→//   - Abort handling uses error.name === 'AbortError' (not DOMException)
  7→//   - Uses session's existing project_id from SQLite (not re-derived hash)
  8→
  9→import { randomUUID } from 'crypto';
 10→import { jsonrepair } from 'jsonrepair';
 11→import { getDb } from '@code-insights/cli/db/client';
 12→import { createLLMClient, isLLMConfigured } from './client.js';
 13→import {
 14→  SESSION_ANALYSIS_SYSTEM_PROMPT,
 15→  generateSessionAnalysisPrompt,
 16→  formatMessagesForAnalysis,
 17→  parseAnalysisResponse,
 18→  PROMPT_QUALITY_SYSTEM_PROMPT,
 19→  generatePromptQualityPrompt,
 20→  parsePromptQualityResponse,
 21→  FACET_ONLY_SYSTEM_PROMPT,
 22→  generateFacetOnlyPrompt,
 23→  extractJsonPayload,
 24→  type SQLiteMessageRow,
 25→  type AnalysisResponse,
 26→  type PromptQualityResponse,
 27→  type ParseError,
 28→} from './prompts.js';
 29→
 30→// Re-export SQLiteMessageRow so routes can import it from analysis.ts directly
 31→export type { SQLiteMessageRow };
 32→
 33→// Maximum tokens to send to LLM (leaving room for response)
 34→const MAX_INPUT_TOKENS = 80000;
 35→const ANALYSIS_VERSION = '3.0.0';
 36→
 37→export interface AnalysisProgress {
 38→  phase: 'loading_messages' | 'analyzing' | 'saving';
 39→  currentChunk?: number;
 40→  totalChunks?: number;
 41→}
 42→
 43→export interface AnalysisOptions {
 44→  onProgress?: (progress: AnalysisProgress) => void;
 45→  signal?: AbortSignal;
 46→}
 47→
 48→export interface AnalysisResult {
 49→  success: boolean;
 50→  insights: InsightRow[];
 51→  error?: string;
 52→  error_type?: string;
 53→  response_length?: number;
 54→  response_preview?: string;
 55→  usage?: {
 56→    inputTokens: number;
 57→    outputTokens: number;
 58→  };
 59→}
 60→
 61→// Re-export ParseError so routes can import it from analysis.ts
 62→export type { ParseError };
 63→
 64→// Shape of a saved insight row (matches the SQLite schema)
 65→export interface InsightRow {
 66→  id: string;
 67→  session_id: string;
