399→/**
400→ * Find recurring patterns across multiple insights and write bidirectional links to SQLite.
401→ */
402→export async function findRecurringInsights(
403→  insights: Array<{
404→    id: string;
405→    type: string;
406→    title: string;
407→    summary: string;
408→    project_name: string;
409→    session_id: string;
410→  }>
411→): Promise<RecurringInsightResult> {
412→  if (!isLLMConfigured()) {
413→    return { success: false, groups: [], updatedCount: 0, error: 'LLM not configured.' };
414→  }
415→
416→  const candidates = insights
417→    .filter(i => i.type !== 'summary' && i.type !== 'prompt_quality')
418→    .slice(0, 200);
419→
420→  if (candidates.length < 2) {
421→    return {
422→      success: false,
423→      groups: [],
424→      updatedCount: 0,
425→      error: 'Need at least 2 non-summary insights to find patterns.',
426→    };
427→  }
428→
429→  try {
430→    const client = createLLMClient();
431→
432→    const insightData = candidates.map(i => ({
433→      id: i.id,
434→      type: i.type === 'technique' ? 'learning' : i.type,
435→      title: i.title,
436→      summary: i.summary.slice(0, 150),
437→      projectName: i.project_name,
438→      sessionId: i.session_id,
439→    }));
440→
441→    const prompt = `Analyze these insights from coding sessions and find groups of semantically similar or duplicate insights — ones that express the same learning or decision even if worded differently.
442→
443→RULES:
444→- Only group insights that are genuinely about the same concept/topic
445→- Insights in a group should be from DIFFERENT sessions (same sessionId = not recurring)
446→- A group must have at least 2 insights
447→- An insight can only belong to one group
448→- Provide a brief "theme" describing what the group shares
449→- If no recurring patterns exist, return an empty groups array
450→
451→INSIGHTS:
452→${JSON.stringify(insightData, null, 2)}
453→
454→Respond with valid JSON only:
455→{
456→  "groups": [
457→    {
458→      "insightIds": ["insight_abc", "insight_def"],
459→      "theme": "Brief description of the shared concept"
460→    }
461→  ]
462→}`;
463→
464→    const response = await client.chat([
465→      {
466→        role: 'system',
467→        content: 'You are an expert at identifying recurring patterns and themes across software development insights. You find semantically similar insights even when they are worded differently. Respond with valid JSON only.',
468→      },
469→      { role: 'user', content: prompt },
470→    ]);
471→
472→    const jsonMatch = response.content.match(/\{[\s\S]*\}/);
473→    if (!jsonMatch) {
474→      return { success: false, groups: [], updatedCount: 0, error: 'Failed to parse recurring insights response.' };
475→    }
476→
477→    const parsed = JSON.parse(jsonMatch[0]) as { groups: RecurringInsightGroup[] };
478→    const groups = parsed.groups || [];
479→
480→    const validIds = new Set(candidates.map(i => i.id));
481→    const validGroups = groups
482→      .map(g => ({
483→        ...g,
484→        insightIds: g.insightIds.filter(id => validIds.has(id)),
485→      }))
486→      .filter(g => g.insightIds.length >= 2);
487→
488→    if (validGroups.length === 0) {
489→      return {
490→        success: true,
491→        groups: [],
492→        updatedCount: 0,
493→        usage: response.usage
494→          ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
495→          : undefined,
496→      };
497→    }
498→
499→    // Build bidirectional links
500→    const linkMap = new Map<string, string[]>();
501→    for (const group of validGroups) {
502→      for (const id of group.insightIds) {
503→        const others = group.insightIds.filter(otherId => otherId !== id);
504→        const existing = linkMap.get(id) || [];
505→        linkMap.set(id, [...new Set([...existing, ...others])]);
506→      }
507→    }
508→
509→    // Write links to SQLite
510→    const db = getDb();
511→    const updateLinks = db.prepare(
512→      `UPDATE insights SET linked_insight_ids = ? WHERE id = ?`
513→    );
514→
515→    for (const [insightId, linkedIds] of linkMap.entries()) {
516→      updateLinks.run(JSON.stringify(linkedIds), insightId);
517→    }
518→
519→    return {
520→      success: true,
521→      groups: validGroups,
522→      updatedCount: linkMap.size,
523→      usage: response.usage
524→        ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
525→        : undefined,
526→    };
527→  } catch (error) {
528→    return {
529→      success: false,
530→      groups: [],
531→      updatedCount: 0,
532→      error: error instanceof Error ? error.message : 'Failed to find recurring insights',
533→    };
534→  }
535→}
