**3. Replace the effective patterns SQL query** (around lines 113-124):

Current:
```typescript
const effectivePatterns = db.prepare(`
  SELECT
    json_extract(je.value, '$.description') as description,
    COUNT(*) as frequency,
    AVG(json_extract(je.value, '$.confidence')) as avg_confidence
  FROM session_facets sf
  JOIN sessions s ON sf.session_id = s.id
  CROSS JOIN json_each(sf.effective_patterns) je
  ${where}
  GROUP BY description
  ORDER BY frequency DESC, avg_confidence DESC
`).all(...params) as Array<{ description: string; frequency: number; avg_confidence: number }>;
```

New:
```typescript
const rawPatterns = db.prepare(`
  SELECT
    COALESCE(json_extract(je.value, '$.category'), '__uncategorized__') as category,
    json_extract(je.value, '$.description') as description,
    json_extract(je.value, '$.confidence') as confidence
  FROM session_facets sf
  JOIN sessions s ON sf.session_id = s.id
  CROSS JOIN json_each(sf.effective_patterns) je
  ${where}
`).all(...params) as Array<{ category: string; description: string; confidence: number }>;

// Normalize categories and merge (same pattern as friction normalization)
const patternMap = new Map<string, { count: number; total_confidence: number; descriptions: string[] }>();
for (const row of rawPatterns) {
  // Legacy data without category: use description as a fallback grouping key
  const rawCategory = row.category === '__uncategorized__' ? row.description : row.category;
  const normalized = row.category === '__uncategorized__' ? row.description : normalizePatternCategory(rawCategory);
  const existing = patternMap.get(normalized);
  if (existing) {
    existing.count += 1;
    existing.total_confidence += (row.confidence ?? 80);
    if (!existing.descriptions.includes(row.description)) {
      existing.descriptions.push(row.description);
    }
  } else {
    patternMap.set(normalized, {
      count: 1,
      total_confidence: row.confidence ?? 80,
      descriptions: [row.description],
    });
  }
}

const effectivePatterns: AggregatedEffectivePattern[] = Array.from(patternMap.entries())
  .map(([category, data]) => ({
    category,
    label: PATTERN_CATEGORY_LABELS[category] ?? category.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
    frequency: data.count,
    avg_confidence: data.total_confidence / data.count,
    descriptions: data.descriptions.slice(0, 10),
  }))
  .sort((a, b) => b.frequency - a.frequency || b.avg_confidence - a.avg_confidence);
```

