 15→// Rough token estimate per insight (title + content + metadata summary).
 16→// Used to enforce the hard 60k input token ceiling within the depth cap.
 17→const AVG_TOKENS_PER_INSIGHT = 300;
 18→const MAX_EXPORT_INPUT_TOKENS = 60000;
