 42→/**
 43→ * Apply depth cap and token budget guard, returning the insights to send to the LLM.
 44→ * Also returns totalInsights (before cap) for metadata.
 45→ */
 46→export function applyDepthCap(
 47→  insights: ExportInsightRow[],
 48→  depth: ExportDepth
 49→): { capped: ExportInsightRow[]; totalInsights: number } {
 50→  const totalInsights = insights.length;
 51→  const depthCap = DEPTH_CAPS[depth];
 52→
 53→  // Apply depth cap first
 54→  let capped = insights.slice(0, depthCap);
 55→
 56→  // Token budget guard within the depth cap — safety net for unusually large insights
 57→  let tokenEstimate = 0;
 58→  const tokenBudgeted: ExportInsightRow[] = [];
 59→  for (const insight of capped) {
 60→    tokenEstimate += AVG_TOKENS_PER_INSIGHT;
 61→    if (tokenEstimate > MAX_EXPORT_INPUT_TOKENS) break;
 62→    tokenBudgeted.push(insight);
 63→  }
 64→  capped = tokenBudgeted;
 65→
 66→  return { capped, totalInsights };
 67→}
