626→    return {
627→      success: false,
628→      error: { error_type: 'no_json_found', error_message: 'No JSON found in prompt quality response', response_length, response_preview: preview },
629→    };
630→  }
631→
632→  let parsed: PromptQualityResponse;
633→  try {
634→    parsed = JSON.parse(jsonPayload) as PromptQualityResponse;
635→  } catch {
636→    try {
637→      parsed = JSON.parse(jsonrepair(jsonPayload)) as PromptQualityResponse;
638→    } catch (err) {
639→      const msg = err instanceof Error ? err.message : String(err);
640→      console.error('Failed to parse prompt quality response (after jsonrepair):', err);
641→      return {
642→        success: false,
643→        error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
644→      };
645→    }
646→  }
647→
648→  if (typeof parsed.efficiencyScore !== 'number') {
