656→  parsed.efficiencyScore = Math.max(0, Math.min(100, Math.round(parsed.efficiencyScore)));
657→  parsed.potentialMessageReduction = parsed.potentialMessageReduction || 0;
658→  parsed.overallAssessment = parsed.overallAssessment || '';
659→  parsed.wastedTurns = parsed.wastedTurns || [];
660→  parsed.antiPatterns = parsed.antiPatterns || [];
661→  parsed.sessionTraits = parsed.sessionTraits || [];
662→  parsed.tips = parsed.tips || [];
663→
664→  return { success: true, data: parsed };
665→}
