 95→ * Analyze a session and generate insights, saving them to SQLite.
 96→ */
 97→export async function analyzeSession(
 98→  session: SessionData,
 99→  messages: SQLiteMessageRow[],
100→  options?: AnalysisOptions
101→): Promise<AnalysisResult> {
102→  if (!isLLMConfigured()) {
103→    return {
104→      success: false,
105→      insights: [],
106→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
107→    };
108→  }
109→
110→  if (messages.length === 0) {
111→    return {
112→      success: false,
113→      insights: [],
114→      error: 'No messages found for this session.',
115→    };
116→  }
117→
118→  try {
119→    const client = createLLMClient();
120→    const formattedMessages = formatMessagesForAnalysis(messages);
121→    const estimatedTokens = client.estimateTokens(formattedMessages);
122→
123→    let analysisResponse: AnalysisResponse;
124→    let totalInputTokens = 0;
125→    let totalOutputTokens = 0;
126→
127→    if (estimatedTokens > MAX_INPUT_TOKENS) {
128→      // Chunk the messages and analyze separately
129→      const chunks = chunkMessages(messages, client.estimateTokens.bind(client));
130→      const chunkResponses: AnalysisResponse[] = [];
131→      const totalChunks = chunks.length;
132→
133→      for (let i = 0; i < chunks.length; i++) {
134→        const chunk = chunks[i];
135→        options?.onProgress?.({ phase: 'analyzing', currentChunk: i + 1, totalChunks });
136→
137→        const chunkFormatted = formatMessagesForAnalysis(chunk);
138→        const prompt = generateSessionAnalysisPrompt(
139→          session.project_name,
140→          session.summary,
141→          chunkFormatted
142→        );
143→
144→        const response = await client.chat([
145→          { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
146→          { role: 'user', content: prompt },
147→        ], { signal: options?.signal });
148→
149→        if (response.usage) {
150→          totalInputTokens += response.usage.inputTokens;
151→          totalOutputTokens += response.usage.outputTokens;
152→        }
153→
154→        const parsed = parseAnalysisResponse(response.content);
155→        if (parsed.success) chunkResponses.push(parsed.data);
156→      }
157→
158→      if (chunkResponses.length === 0) {
159→        return {
160→          success: false,
161→          insights: [],
162→          error: 'All chunks failed to parse LLM response',
163→          error_type: 'json_parse_error',
164→          usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
165→        };
166→      }
167→
168→      analysisResponse = mergeAnalysisResponses(chunkResponses);
169→
170→      // Chunked sessions: extract facets separately using lightweight prompt
171→      // (facets are holistic — can't be merged across chunks)
172→      if (!analysisResponse.facets) {
173→        try {
174→          const firstMsgs = formatMessagesForAnalysis(messages.slice(0, 20));
175→          const lastMsgs = formatMessagesForAnalysis(messages.slice(-20));
176→          const facetPrompt = generateFacetOnlyPrompt(
177→            session.project_name,
178→            session.summary,
179→            firstMsgs,
180→            lastMsgs
181→          );
182→
183→          const facetResponse = await client.chat([
184→            { role: 'system', content: FACET_ONLY_SYSTEM_PROMPT },
185→            { role: 'user', content: facetPrompt },
186→          ], { signal: options?.signal });
187→
188→          if (facetResponse.usage) {
189→            totalInputTokens += facetResponse.usage.inputTokens;
190→            totalOutputTokens += facetResponse.usage.outputTokens;
191→          }
192→
193→          const facetJson = extractJsonPayload(facetResponse.content);
194→          if (facetJson) {
195→            try {
196→              analysisResponse.facets = JSON.parse(facetJson);
197→            } catch {
198→              // jsonrepair fallback
199→              try {
200→                analysisResponse.facets = JSON.parse(jsonrepair(facetJson));
201→              } catch {
202→                // Facet extraction failed for chunked session — non-fatal
203→              }
204→            }
205→          }
206→        } catch {
207→          // Facet extraction failed for chunked session — non-fatal, continue
208→        }
209→      }
210→    } else {
211→      options?.onProgress?.({ phase: 'analyzing', currentChunk: 1, totalChunks: 1 });
212→      const prompt = generateSessionAnalysisPrompt(
213→        session.project_name,
214→        session.summary,
215→        formattedMessages
216→      );
217→
218→      const response = await client.chat([
219→        { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
220→        { role: 'user', content: prompt },
221→      ], { signal: options?.signal });
222→
223→      if (response.usage) {
224→        totalInputTokens = response.usage.inputTokens;
225→        totalOutputTokens = response.usage.outputTokens;
226→      }
227→
228→      const parsed = parseAnalysisResponse(response.content);
229→      if (!parsed.success) {
230→        return {
231→          success: false,
232→          insights: [],
233→          error: 'Failed to parse LLM response. Please try again.',
234→          error_type: parsed.error.error_type,
235→          response_length: parsed.error.response_length,
236→          response_preview: parsed.error.response_preview,
237→        };
238→      }
239→
240→      analysisResponse = parsed.data;
241→    }
242→
243→    options?.onProgress?.({ phase: 'saving' });
244→    const insights = convertToInsightRows(analysisResponse, session);
245→
246→    // Save new insights first, then delete old non-prompt-quality insights
247→    // (safe order: if save fails, old data is preserved)
248→    saveInsightsToDb(insights);
249→    deleteSessionInsights(session.id, {
250→      excludeTypes: ['prompt_quality'],
251→      excludeIds: insights.map(i => i.id),
252→    });
253→
254→    // Save facets if extracted
255→    if (analysisResponse.facets) {
256→      saveFacetsToDb(session.id, analysisResponse.facets, ANALYSIS_VERSION);
257→    }
258→
259→    // Update session character if LLM classified it
260→    if (analysisResponse.session_character) {
261→      const db = getDb();
262→      db.prepare('UPDATE sessions SET session_character = ? WHERE id = ?')
263→        .run(analysisResponse.session_character, session.id);
264→    }
265→
266→    return {
267→      success: true,
268→      insights,
269→      usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
270→    };
271→  } catch (error) {
272→    if (error instanceof Error && error.name === 'AbortError') {
273→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
274→    }
275→    return {
276→      success: false,
277→      insights: [],
278→      error: error instanceof Error ? error.message : 'Analysis failed',
279→      error_type: 'api_error',
280→    };
281→  }
282→}
