284→/**
285→ * Analyze prompt quality for a session.
286→ */
287→export async function analyzePromptQuality(
288→  session: SessionData,
289→  messages: SQLiteMessageRow[],
290→  options?: AnalysisOptions
291→): Promise<AnalysisResult> {
292→  if (!isLLMConfigured()) {
293→    return {
294→      success: false,
295→      insights: [],
296→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
297→    };
298→  }
299→
300→  if (messages.length === 0) {
301→    return {
302→      success: false,
303→      insights: [],
304→      error: 'No messages found for this session.',
305→    };
306→  }
307→
308→  const userMessages = messages.filter(m => m.type === 'user');
309→  if (userMessages.length < 2) {
310→    return {
311→      success: false,
312→      insights: [],
313→      error: 'Not enough user messages to analyze prompt quality (need at least 2).',
314→    };
315→  }
316→
317→  try {
318→    const client = createLLMClient();
319→    const formattedMessages = formatMessagesForAnalysis(messages);
320→
321→    let analysisInput = formattedMessages;
322→    const estimatedTokens = client.estimateTokens(formattedMessages);
323→    if (estimatedTokens > MAX_INPUT_TOKENS) {
324→      const targetLength = Math.floor((MAX_INPUT_TOKENS / estimatedTokens) * formattedMessages.length * 0.8);
325→      analysisInput = formattedMessages.slice(0, targetLength) + '\n\n[... conversation truncated for analysis ...]';
326→    }
327→
328→    const prompt = generatePromptQualityPrompt(
329→      session.project_name,
330→      analysisInput,
331→      messages.length
332→    );
333→
334→    options?.onProgress?.({ phase: 'analyzing' });
335→    const response = await client.chat([
336→      { role: 'system', content: PROMPT_QUALITY_SYSTEM_PROMPT },
337→      { role: 'user', content: prompt },
338→    ], { signal: options?.signal });
339→
340→    const parsed = parsePromptQualityResponse(response.content);
341→    if (!parsed.success) {
342→      return {
343→        success: false,
344→        insights: [],
345→        error: 'Failed to parse prompt quality analysis. Please try again.',
346→        error_type: parsed.error.error_type,
347→        response_length: parsed.error.response_length,
348→        response_preview: parsed.error.response_preview,
349→      };
350→    }
351→
352→    options?.onProgress?.({ phase: 'saving' });
353→    const insight = convertPromptQualityToInsightRow(parsed.data, session);
354→
355→    // Save new insight, then delete old prompt_quality insights
356→    saveInsightsToDb([insight]);
357→    deleteSessionInsights(session.id, {
358→      includeOnlyTypes: ['prompt_quality'],
359→      excludeIds: [insight.id],
360→    });
361→
362→    return {
363→      success: true,
364→      insights: [insight],
365→      usage: response.usage ? {
366→        inputTokens: response.usage.inputTokens,
367→        outputTokens: response.usage.outputTokens,
368→      } : undefined,
369→    };
370→  } catch (error) {
371→    if (error instanceof Error && error.name === 'AbortError') {
372→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
373→    }
374→    return {
375→      success: false,
376→      insights: [],
377→      error: error instanceof Error ? error.message : 'Prompt quality analysis failed',
378→      error_type: 'api_error',
379→    };
380→  }
381→}
