748→/**
749→ * Write insight rows to SQLite using prepared statements.
750→ */
751→function saveInsightsToDb(insights: InsightRow[]): void {
752→  const db = getDb();
753→  const insert = db.prepare(`
754→    INSERT OR REPLACE INTO insights (
755→      id, session_id, project_id, project_name, type, title, content,
756→      summary, bullets, confidence, source, metadata, timestamp,
757→      created_at, scope, analysis_version
758→    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
759→  `);
760→
761→  const insertMany = db.transaction((rows: InsightRow[]) => {
762→    for (const row of rows) {
763→      insert.run(
764→        row.id,
765→        row.session_id,
766→        row.project_id,
767→        row.project_name,
768→        row.type,
769→        row.title,
770→        row.content,
771→        row.summary,
772→        row.bullets,
773→        row.confidence,
774→        row.source,
775→        row.metadata,
776→        row.timestamp,
777→        row.created_at,
778→        row.scope,
779→        row.analysis_version,
780→      );
781→    }
782→  });
783→
784→  insertMany(insights);
785→}
