819→/**
820→ * Save extracted facets to the session_facets table.
821→ */
822→function saveFacetsToDb(
823→  sessionId: string,
824→  facets: NonNullable<AnalysisResponse['facets']>,
825→  analysisVersion: string
826→): void {
827→  const db = getDb();
828→  db.prepare(`
829→    INSERT OR REPLACE INTO session_facets
830→    (session_id, outcome_satisfaction, workflow_pattern, had_course_correction,
831→     course_correction_reason, iteration_count, friction_points, effective_patterns,
832→     analysis_version)
833→    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
834→  `).run(
835→    sessionId,
836→    facets.outcome_satisfaction,
837→    facets.workflow_pattern,
838→    facets.had_course_correction ? 1 : 0,
839→    facets.course_correction_reason,
840→    facets.iteration_count,
841→    JSON.stringify(Array.isArray(facets.friction_points) ? facets.friction_points : []),
842→    JSON.stringify(Array.isArray(facets.effective_patterns) ? facets.effective_patterns : []),
843→    analysisVersion
844→  );
845→}
