 27→// Friction bar severity color based on avg_severity (1=low, 2=medium, 3=high)
 28→function frictionBarColor(avgSeverity: number): string {
 29→  if (avgSeverity >= 2.5) return '#ef4444'; // red-500 (high)
 30→  if (avgSeverity >= 2.0) return '#f97316'; // orange-500
 31→  if (avgSeverity >= 1.5) return '#f59e0b'; // amber-500
 32→  return '#22c55e'; // green-500 (low)
 33→}
