561→                          </div>
562→                          <Button
563→                            variant="ghost"
564→                            size="icon"
565→                            className="h-8 w-8 shrink-0"
566→                            onClick={() => handleCopy(h.command, `hook-${i}`)}
567→                          >
568→                            {copiedKey === `hook-${i}` ? <Check className="h-3.5 w-3.5 text-green-500" /> : <Copy className="h-3.5 w-3.5" />}
569→                          </Button>
570→                        </div>
571→                        <p className="text-xs text-muted-foreground mt-2">{h.rationale}</p>
572→                      </div>
573→                    ))}
574→                  </CardContent>
575→                </Card>
576→              )}
577→            </>
578→          ) : (
579→            /* Pattern Ingredients fallback — before generation */
580→            aggregation && (
581→              <Card>
582→                <CardHeader>
583→                  <CardTitle className="text-base">Pattern Ingredients</CardTitle>
584→                  <CardDescription>
585→                    {hasEnoughFacets
586→                      ? 'Click Generate to create rules and hooks from these patterns.'
587→                      : 'Analyze more sessions to unlock pattern synthesis.'}
588→                  </CardDescription>
589→                </CardHeader>
590→                <CardContent className="space-y-4">
591→                  {aggregation.frictionCategories.filter(fc => fc.count >= 3).length > 0 && (
592→                    <div>
593→                      <p className="text-xs font-medium text-muted-foreground mb-2">Recurring friction (3+ occurrences):</p>
594→                      <ul className="space-y-1">
595→                        {aggregation.frictionCategories.filter(fc => fc.count >= 3).map((fc, i) => (
596→                          <li key={i} className="text-sm flex items-center gap-2">
597→                            <span className="text-xs font-mono text-muted-foreground">{fc.count}x</span>
598→                            {fc.category}
599→                          </li>
600→                        ))}
601→                      </ul>
602→                    </div>
603→                  )}
604→                  {aggregation.effectivePatterns.filter(ep => ep.frequency >= 2).length > 0 && (
605→                    <div>
606→                      <p className="text-xs font-medium text-muted-foreground mb-2">Effective patterns (2+ occurrences):</p>
607→                      <ul className="space-y-1">
608→                        {aggregation.effectivePatterns.filter(ep => ep.frequency >= 2).map((ep, i) => (
609→                          <li key={i} className="text-sm flex items-center gap-2">
610→                            <span className="text-xs font-mono text-muted-foreground">{ep.frequency}x</span>
611→                            {ep.description}
612→                          </li>
613→                        ))}
614→                      </ul>
615→                    </div>
616→                  )}
617→                  {aggregation.frictionCategories.filter(fc => fc.count >= 3).length === 0 &&
618→                   aggregation.effectivePatterns.filter(ep => ep.frequency >= 2).length === 0 && (
619→                    <p className="text-sm text-muted-foreground">
620→                      No recurring patterns yet. Analyze more sessions to detect patterns.
621→                    </p>
622→                  )}
623→                </CardContent>
624→              </Card>
625→            )
626→          )}
627→        </TabsContent>
628→      </Tabs>
629→    </div>
630→  );
631→}
